INSERT INTO `article` (`id`, `title`, `priority`, `description`, `content`, `image`, `tags`, `author`, `status`, `view`, `publish_date`, `template`, `created_at`, `updated_at`, `raw_text`) VALUES
(1, '5.5m Thang Nhôm Thẳng Poongsan 3055-1', 1000, '5.5m Thang Nhôm Thẳng Poongsan 3055-1 hàng chính hãng, gọi ngay để được tư vấn, giá tốt.', '<div itemprop=\"description\">\n<p>5.5m Thang Nh&ocirc;m Thẳng Poongsan 3055-1 h&agrave;ng ch&iacute;nh h&atilde;ng, gọi ngay để được tư vấn, gi&aacute; tốt.</p>\n</div>\n<div class=\"product_meta\"><span class=\"sku_wrapper\">Thương hiệu:<span>&nbsp;</span><span class=\"sku\">POONGSAN<br /></span></span><span class=\"sku_wrapper\">M&atilde; sản phẩm:<span>&nbsp;</span><span class=\"sku\">3055-1<br /></span></span><span class=\"sku_wrapper\">Xuất xứ:<span>&nbsp;</span><span class=\"sku\">H&agrave;n Quốc<br /></span></span><span class=\"sku_wrapper\">Bảo h&agrave;nh:<span>&nbsp;</span><span class=\"sku\">12 Th&aacute;ng<br /></span></span><span class=\"sku_wrapper\">T&igrave;nh trạng:<span>&nbsp;</span><span class=\"sku\">C&ograve;n H&agrave;ng</span></span></div>', 's-gallery-3-180x180_1576661368.jpg', '', '', 'inactive', 13, '2019-12-19 09:44:08', '', '2019-12-19 02:44:08', '2020-04-23 19:01:38', '5.5m thang nhom thang poongsan 3055-1'),
(2, 'Phải tiết kiệm ngân sách khi mua sắm?', 1000, 'Samsung tiếp tục chứng tỏ vị thế của mình tại Việt Nam với loạt sản phẩm bình dân đến cao cấp và họ cũng là nhà sản xuất có nhiều sản phẩm bán chạy nhất tháng 4/2015.', '<div class=\"wpb_text_column wpb_content_element \">\n<div class=\"wpb_wrapper\">\n<p>Samsung tiếp tục chứng tỏ vị thế của m&igrave;nh tại Việt Nam với loạt sản phẩm b&igrave;nh d&acirc;n đến cao cấp v&agrave; họ cũng l&agrave; nh&agrave; sản xuất c&oacute; nhiều sản phẩm b&aacute;n chạy nhất th&aacute;ng 4/2015.</p>\n</div>\n</div>\n<div class=\"vc_empty_space\"><span class=\"vc_empty_space_inner\"></span></div>\n<blockquote class=\"qodef-blockquote-shortcode\">\n<h4 class=\"qodef-blockquote-text\"><span>Theo bảng thống k&ecirc; những smartphone b&aacute;n chạy th&aacute;ng 4/2015 từ nh&agrave; b&aacute;n lẻ FPTShop, Thế giới Di động, Mai Nguy&ecirc;n... Samsung c&oacute; đến 5 sản phẩm nằm trong top 10 sản phẩm b&aacute;n chạy nhất th&aacute;ng, c&aacute;c vị tr&iacute; c&ograve;n lại nhường chỗ cho Apple, Microsoft v&agrave; Oppo.</span></h4>\n</blockquote>\n<div class=\"vc_empty_space\"><span class=\"vc_empty_space_inner\"></span></div>\n<div class=\"wpb_text_column wpb_content_element \">\n<div class=\"wpb_wrapper\">\n<p>Tương tự như những th&aacute;ng trước đ&oacute;, th&aacute;ng 4 năm nay tiếp tục chứng kiến vị thế của smartphone tầm trung trong mắt người ti&ecirc;u d&ugrave;ng Việt. Hầu hết c&aacute;c sản phẩm b&aacute;n chạy đều c&oacute; mức gi&aacute; từ 5 triệu đồng trở lại. Trong khi đ&oacute;, ph&acirc;n kh&uacute;c cao cấp chỉ c&oacute; sự xuất hiện của ba sản phẩm ch&iacute;nh v&agrave; cũng l&agrave; đối thủ truyền kiếp đ&oacute; l&agrave; Apple với iPhone 6 v&agrave; Samsung c&oacute; mẫu Galaxy S6 v&agrave; Galaxy S6 edge.</p>\n</div>\n</div>\n<div class=\"vc_empty_space\"><span class=\"vc_empty_space_inner\"></span></div>\n<div class=\"wpb_text_column wpb_content_element \">\n<div class=\"wpb_wrapper\">\n<p>&Ocirc;ng Vũ Ngọc Thắng, Ph&oacute; Gi&aacute;m đốc ng&agrave;nh h&agrave;ng điện thoại của hệ thống b&aacute;n lẻ FPT Shop, cho biết: &ldquo;Ph&acirc;n kh&uacute;c điện thoại gi&aacute; rẻ tầm trung dưới 3 triệu vẫn sẽ được người d&ugrave;ng tin tưởng lựa chọn sử dụng. Hiện nay, hầu hết kh&aacute;ch h&agrave;ng đều đang ưa chuộng sử dụng c&aacute;c sản phẩm nằm trong ph&acirc;n kh&uacute;c n&agrave;y v&igrave; đ&aacute;p ứng được đầy đủ c&aacute;c chức năng với mức gi&aacute; kh&ocirc;ng qu&aacute; cao&rdquo;.</p>\n</div>\n</div>\n<div class=\"vc_empty_space\"><span class=\"vc_empty_space_inner\"></span></div>\n<div class=\"wpb_text_column wpb_content_element \">\n<div class=\"wpb_wrapper\">\n<p>B&ecirc;n cạnh đ&oacute;, theo đại diện Thế giới Di động, doanh thu smartphone th&aacute;ng 4 đ&atilde; c&oacute; dấu hiệu tăng trưởng trở lại, mức tăng 5%, nhất l&agrave; trong dịp lễ 30/4 vừa qua. Đồng thời, th&aacute;ng 5 được xem l&agrave; th&aacute;ng bắt đầu cho chuỗi phục hồi của thị trường, hứa hẹn mức tăng trưởng tốt.</p>\n</div>\n</div>', 'b-new-news-app-deliveres-fresh-ideas_1576661361.jpg', '#Điện thoại#Máy tính bảng#Thiết bị điện tử#', '', 'inactive', 98, '2019-12-19 10:57:24', '', '2019-12-19 03:57:24', '2020-04-23 19:01:38', 'phai tiet kiem ngan sach khi mua sam?'),
