(11, 'Tư vấn & thiết kế hệ thống ERP (SMB)', 1000, '', 'Tư vấn thế kế ERP (SMB)', '', '', '', 'active', 3182, '2020-09-08 10:32:00', '', '2020-09-08 03:32:33', '2020-09-08 03:33:05', 'tu van & thiet ke he thong erp (smb)'),
(12, 'Tư vấn dịch vụ in ấn', 1000, '', 'Tư vấn kh&aacute;ch h&agrave;ng sử dụng m&aacute;y in, m&aacute;y photocopy ph&ugrave; hợp nhất', '', '', '', 'active', 3392, '2020-09-08 10:38:00', '', '2020-09-08 03:38:10', '2020-09-08 03:40:58', 'tu van dich vu in an'),
