(14, 'Máy tính để bàn mini HP 400 G6 ', 1000, 'Máy tính để bàn mini HP 400 G6 \n', '<table width=\"539\">\n<tbody>\n<tr>\n<td width=\"160\">Model</td>\n<td width=\"379\">M&aacute;y t&iacute;nh để b&agrave;n mini HP 400 G6&nbsp;</td>\n</tr>\n<tr>\n<td width=\"160\">Xuất xứ</td>\n<td width=\"379\">China</td>\n</tr>\n<tr>\n<td width=\"160\">H&atilde;ng sản xuất</td>\n<td width=\"379\">HP</td>\n</tr>\n<tr>\n<td width=\"160\">Bảo h&agrave;nh</td>\n<td width=\"379\">36 th&aacute;ng</td>\n</tr>\n<tr>\n<td width=\"160\">Bộ vi xử l&yacute;</td>\n<td width=\"379\">Intel&reg; Core&trade; i5-10600T (2.4 GHzup to 4.0 GHz with Intel&reg; Turbo Boost Technology, 12 MB L3 cache, 6 cores)</td>\n</tr>\n<tr>\n<td width=\"160\">RAM</td>\n<td width=\"379\">8GB (1x8GB) DDR4</td>\n</tr>\n<tr>\n<td width=\"160\">VGA</td>\n<td width=\"379\">Intel UHD Graphics</td>\n</tr>\n<tr>\n<td width=\"160\">Ổ cứng</td>\n<td width=\"379\">SSD 256GB</td>\n</tr>\n<tr>\n<td rowspan=\"2\" width=\"160\">Ports</td>\n<td width=\"379\">Front: 1 headphone/microphone combo; 1 SuperSpeed USB Type-C&reg; 10Gbps signaling rate; 1 SuperSpeed USB Type-A 10Gbps signaling rate; 1 SuperSpeed USB Type-A 5Gbps signaling rate (charging)</td>\n</tr>\n<tr>\n<td width=\"379\">Rear: 1 RJ-45; 1 DisplayPort&trade; 1.4; 2 SuperSpeed USB Type-A 5Gbps signaling rate; 1 HDMI 1.4b; 2 USB Type-A 480Mbps signaling rate</td>\n</tr>\n<tr>\n<td width=\"160\">Kết nối</td>\n<td width=\"379\">Bluetooth + Wifi Lan</td>\n</tr>\n<tr>\n<td width=\"160\">Hệ điều h&agrave;nh</td>\n<td width=\"379\">Dos</td>\n</tr>\n<tr>\n<td width=\"160\">K&iacute;ch thước</td>\n<td width=\"379\">17.7 x 17.5 x 3.4 cm</td>\n</tr>\n<tr>\n<td width=\"160\">Trọng lượng</td>\n<td width=\"379\">1.25 kg</td>\n</tr>\n<tr>\n<td width=\"160\">Phụ kiện</td>\n<td width=\"379\">Key &amp; Mouse USB</td>\n</tr>\n</tbody>\n</table>', 'hp_400mini_1625371865.jpg', '', '', 'active', 218, '2021-07-04 11:11:58', '', '2021-07-04 04:11:58', '2021-07-04 04:11:58', 'may tinh de ban mini hp 400 g6 '),
(15, 'Laptop HP ProBook 450 G8', 1000, 'Laptop HP ProBook 450 G8', '&nbsp;Hệ điều h&agrave;nh: Windows 11 Home 64 <br />- CPU: Intel&reg; Core&trade; i5-1135G7 (2.4 GHz, up to 4.2 GHz)<br />- RAM: 16GB bus 3200; <br />- SSD: M.2 512GB PCIe NVMe <br />- Cổng giao tiếp: USB Type-A; USB Type-C; HDMI; AC power<br />- Display: 15.6 inch HD (1366x768) <br />- Card đồ họa (VGA): Intel&reg; Iris&reg; Xᵉ<br />- PIN: 3-cell<br />- K&iacute;ch thước: 35.94 x 23.39 x 1.99 cm<br />- Trọng lượng: 1.74 kg<br />- Bảo h&agrave;nh: 3 năm<br />Gi&aacute; 30,470,000', '', '', '', 'active', 169, '2022-07-15 14:20:24', '', '2022-07-15 07:20:24', '2022-07-15 07:20:24', 'laptop hp probook 450 g8'),
(16, 'Mừng Giáng Sinh – Quà Lung Linh', 1000, 'Chương Trình Khuyến Mại mực in AVP', '<div style=\"text-align: center;\"><span style=\"font-size: 20pt;\"><strong>TH&Ocirc;NG B&Aacute;O</strong></span></div>\n<div style=\"text-align: center;\"><strong>V/v Chương Tr&igrave;nh Khuyến Mại </strong></div>\n<div style=\"text-align: center;\"><strong>&ldquo;</strong><strong>Mừng Gi&aacute;ng Sinh &ndash; Qu&agrave; Lung Linh</strong><strong>&rdquo;</strong></div>\n<p>C&ocirc;ng ty TNHH Thương Mại Dịch Vụ <strong>&Acirc;u Việt Ph&aacute;t</strong><strong> (</strong><strong>AVP</strong>), tr&acirc;n trọng gởi lời ch&agrave;o, lời ch&uacute;c sức khỏe v&agrave; th&agrave;nh c&ocirc;ng đến Qu&yacute; Kh&aacute;ch H&agrave;ng, Nh&acirc;n dịp Gi&aacute;ng Sinh &amp; Năm Mới k&iacute;nh ch&uacute;c Qu&yacute; Kh&aacute;ch h&agrave;ng, đối t&aacute;c nhiều <strong>sức khỏe &amp; vạn b&igrave;nh an</strong>. Cảm ơn <strong>Qu&yacute; Kh&aacute;ch h&agrave;ng</strong> đ&atilde; quan t&acirc;m, ủng hộ &amp; đồng h&agrave;ng c&ugrave;ng mực in AVP.</p>\n<p>Đ&aacute;p lại sự tin y&ecirc;u của <strong>Qu&yacute; Kh&aacute;ch h&agrave;ng</strong>, <strong>AVP</strong> xin gởi chương tr&igrave;nh khuyến mại <strong>SI&Ecirc;U HOT</strong>:</p>\n<table>\n<tbody>\n<tr>\n<td width=\"192\">\n<p><strong>Sản phẩm mực in AVP</strong></p>\n</td>\n<td width=\"507\">\n<p><strong>Qu&agrave; Tặng</strong></p>\n</td>\n</tr>\n<tr>\n<td width=\"192\">\n<p>Mua <strong>01</strong> hộp mực AVP</p>\n</td>\n<td width=\"507\">\n<p><strong>Chuột Kh&ocirc;ng D&acirc;y + Bao l&igrave;xi</strong> hoặc <strong>thẻ c&agrave;o 100k + Bao l&igrave;xi</strong></p>\n</td>\n</tr>\n<tr>\n<td width=\"192\">\n<p>Mua <strong>03</strong> hộp mực AVP</p>\n</td>\n<td width=\"507\">\n<p><strong>Tặng thẻ c&agrave;o 400k</strong> + Bao l&igrave; x&igrave; AVP</p>\n</td>\n</tr>\n<tr>\n<td width=\"192\">\n<p>Mua <strong>05</strong> hộp mực AVP</p>\n</td>\n<td width=\"507\">\n<p>Tặng thẻ c&agrave;o <strong>600k</strong> + Bao L&igrave;xi</p>\n</td>\n</tr>\n<tr>\n<td width=\"192\">\n<p>Mua <strong>10</strong> hộp mực AVP</p>\n</td>\n<td width=\"507\">\n<p>Tăng thẻ c&agrave;o <strong>1300k</strong> + Bao lixi + Chuột kh&ocirc;ng d&acirc;y</p>\n</td>\n</tr>\n<tr>\n<td width=\"192\">\n<p>Mua <strong>15</strong> hộp mực AVP</p>\n</td>\n<td width=\"507\">\n<p>Tặng thẻ c&agrave;o <strong>1900k</strong> + Bao lixi + Pin dự ph&ograve;ng</p>\n</td>\n</tr>\n<tr>\n<td width=\"192\">\n<p>Mua <strong>20</strong> hộp mực AVP</p>\n</td>\n<td width=\"507\">\n<p>Tặng m&aacute;y in Canon 6030 hoặc tương đương hoặc Thẻ cảo <strong>2,500K</strong></p>\n</td>\n</tr>\n<tr>\n<td width=\"192\">\n<p>Mua <strong>50</strong> hộp mực AVP</p>\n</td>\n<td width=\"507\">\n<p>Tặng m&aacute;y in HP 404 hoặc tương đương hoặc Thẻ c&agrave;o <strong>5,800k</strong></p>\n</td>\n</tr>\n</tbody>\n</table>\n<p><strong><em><u>Ghi ch&uacute;</u></em></strong><strong>:&nbsp; </strong><strong>Thể lệ tham gia &amp; thủ tục nhận qu&agrave;: </strong></p>\n<ul>\n<li>Qu&agrave; tặng <strong>KH&Ocirc;NG</strong> c&oacute; gi&aacute; trị quy đổi th&agrave;nh tiền mặt &amp; đối trừ c&ocirc;ng nợ.</li>\n<li>M&atilde; mực tham gia khuyến m&atilde;i: <strong>AVP</strong> <strong>05A/ 80A/ 49A/ 12A/ 85A/76A/ 26A/55A/ 107A/ 87A/ TN 3448/ TN2385/ TN1010.</strong></li>\n<li>Qu&yacute; Kh&aacute;ch h&agrave;ng được <strong>cộng dồn</strong> trong thời gian khuyến mại</li>\n<li><strong>Thời gian khuyến mại từ</strong><strong>: </strong><strong>24</strong><strong>/12/2022 - 19/01/2023</strong><strong>.&nbsp;</strong></li>\n<li>Chương tr&igrave;nh khuyến mại <strong>KH&Ocirc;NG</strong> &aacute;p dụng h&agrave;ng dự &aacute;n (<strong>gi&aacute; Hợp Đồng</strong>) v&agrave; đ&atilde; tham gia chương tr&igrave;nh kh&aacute;c v&agrave; <strong>KH&Ocirc;NG</strong> &aacute;p dụng cho h&agrave;ng tồn kho.</li>\n<li>Phương thức nhận qu&agrave;: sau khi kết th&uacute;c chương tr&igrave;nh, trong v&ograve;ng 5 &ndash; 10 ng&agrave;y AVP sẽ gởi qu&agrave; về tận nơi kh&aacute;ch h&agrave;ng. Mọi sự tranh chấp, quyền quyết định ở AVP.</li>\n</ul>\n<p>Rất mong tiếp tục nhận được sự y&ecirc;u Thương, tin tưởng, đồng h&agrave;nh c&ugrave;ng <strong>Qu&yacute; Kh&aacute;ch H&agrave;ng</strong>.</p>\n<p>Tr&acirc;n trọng.</p>', 'avp_muc-in_1587524255.jpg', '#AVP Toner#', '', 'active', 887, '2022-12-24 16:42:00', '', '2022-12-24 09:42:11', '2022-12-24 10:16:42', 'mung giang sinh – qua lung linh'),
(17, 'Giải pháp Mực 151A ', 1000, 'Mực AVP 151A cho các máy in HP mới 4003/ 4103', 'H&atilde;y tr&atilde;i nghiệm mực AVP 151A gi&agrave;nh cho c&aacute;c d&ograve;ng m&aacute;y in HP mới Laserjet 4003DN/ DW &amp; 4103DW', '', '', '', 'active', 690, '2023-05-06 08:29:15', '', '2023-05-06 01:29:15', '2023-05-06 01:29:15', 'giai phap muc 151a '),
(18, 'Draytek 2962', 1000, 'https://www.anphat.vn/san-pham/router/draytek-vigor2962-high-performance-enterprise-dual-wan-vpn-router', '<div class=\"product_title\">\n<h1>DrayTek Vigor2962</h1>\n</div>\n<div class=\"product_desc_short\">\n<p><strong><span>Router VPN hiệu năng cao d&agrave;nh cho Doanh nghiệp, Hotel, Resort ... Hỗ trợ WiFi Marketing </span></strong></p>\n<p>4 cổng WAN/LAN Switchable (chuyển đổi WAN/LAN linh hoạt v&agrave; cho ph&eacute;p chạy đối đa 2 WAN đồng thời):</p>\n<ul>\n<li>1 port 2.5 Gigabit WAN, RJ-45</li>\n<li>1 port Gigabit WAN RJ45 / SFP Combo</li>\n<li>2 port Gigabit WAN / LAN RJ45 thay đổi linh hoạt&nbsp;</li>\n<li>2 port LAN Gigabit RJ-45</li>\n<li>2 port USB d&ugrave;ng kết nối thiết bị lưu trữ&nbsp;</li>\n<li>Multi-WAN Load Balancing &amp; Failover, hỗ trợ đường truyền đa dịch vụ (IPTV, Internet, VoIP...).</li>\n<li>NAT Session: 300.000, NAT Throughtput: 2.2Gb/s với khả năng chịu tải l&ecirc;n đến 300 user</li>\n<li>Hỗ trợ triển khai nhiều dịch vụ cao cấp: Leased line, L2VPN, L3VPN, MetroNET, Static IP, PPOE, PPTP/L2TP, DHCP</li>\n<li>VLAN Tag 802.1q Hỗ trợ chia 20 lớp mạng kh&aacute;c nhau, DMZ LAN, IP routed LAN.</li>\n<li>VPN server 200 k&ecirc;nh đồng thời, IPSec (IKEv1, IKEv2, XAuth), trong đ&oacute; c&oacute; 50 k&ecirc;nh OpenVPN, SSL VPN...., VPN Trunking (Load balancing/Backup).</li>\n<li>T&iacute;ch hợp Wi-Fi Marketing từ c&aacute;c nh&agrave; ph&aacute;t triển h&agrave;ng đầu như Meganet, VNWIFI, Nextify...</li>\n<li>Kiểm so&aacute;t v&agrave; quản l&yacute; băng th&ocirc;ng tối ưu đường truyền Internet, chế độ Hight-Availability.</li>\n<li>Firewall mạnh mẽ, linh hoạt (IP/MAC Address, Port Service, URL/Web Content Filter...), Firewall SPI dựa tr&ecirc;n đối tượng, quản l&yacute; nội dung (CSM).</li>\n<li>DrayDDNS t&ecirc;n miền động miễn ph&iacute; của DrayTek</li>\n<li>Quản l&yacute; tập trung cho 50 Access Point (APM), 30 Switch (SWM)</li>\n<li>Quản l&yacute; tập trung Vigor2962 bằng phần mềm DrayTek VigorACS 2 hoặc Cloud DrayTek Free</li>\n</ul>\n</div>', '', '', '', 'active', 71, '2024-09-12 08:43:29', '', '2024-09-12 01:43:29', '2024-09-12 01:43:29', 'draytek 2962'),
(19, 'Thuê Photocopy Scan miễn phí', 1000, 'Khách hàng thuê photocopy Ricoh được miễn phí Scan, không giới hạn!', '', '', '', '', 'active', 74, '2025-02-20 22:34:00', '', '2025-02-20 15:34:04', '2025-02-20 15:34:30', 'photocopy scan mien phi'),
(20, 'AVP Kỷ Niệm 15 năm Thành Lập', 1000, 'AVP Kết Nối - Đồng Hành & Phát triển ', '<a href=\"https://locator.hp.com/vn/vi/?ml___lang=vi-VI%20(1)&amp;ml___region=VN&amp;ml___cont=APJ&amp;ml___tags[]=\">https://locator.hp.com/vn/vi/?ml___lang=vi-VI%20(1)&amp;ml___region=VN&amp;ml___cont=APJ&amp;ml___tags[]=</a><br /><br />Partner HP', '', '', '', 'active', 46, '2025-03-22 08:06:00', '', '2025-03-22 01:06:32', '2025-03-22 01:09:34', 'avp ky niem 15 nam thanh lap');
INSERT INTO `article_translations` (`id`, `article_id`, `lang`, `title`, `description`, `content`, `created_at`, `updated_at`) VALUES
(1, 1, 'en', '5.5m Thang Nhôm Thẳng Poongsan 3055-1(EN)', '5.5m Thang Nhôm Thẳng Poongsan 3055-1 hàng chính hãng, gọi ngay để được tư vấn, giá tốt.(EN)', '<div itemprop=\"description\">\n<p>5.5m Thang Nh&ocirc;m Thẳng Poongsan 3055-1 h&agrave;ng ch&iacute;nh h&atilde;ng, gọi ngay để được tư vấn, gi&aacute; tốt.</p>\n</div>\n<div class=\"product_meta\"><span class=\"sku_wrapper\">Thương hiệu:<span>&nbsp;</span><span class=\"sku\">POONGSAN<br /></span></span><span class=\"sku_wrapper\">M&atilde; sản phẩm:<span>&nbsp;</span><span class=\"sku\">3055-1<br /></span></span><span class=\"sku_wrapper\">Xuất xứ:<span>&nbsp;</span><span class=\"sku\">H&agrave;n Quốc<br /></span></span><span class=\"sku_wrapper\">Bảo h&agrave;nh:<span>&nbsp;</span><span class=\"sku\">12 Th&aacute;ng<br /></span></span><span class=\"sku_wrapper\">T&igrave;nh trạng:<span>&nbsp;</span><span class=\"sku\">C&ograve;n H&agrave;ng</span></span></div>', '2019-12-19 02:44:08', '2019-12-19 02:44:08'),
(2, 2, 'en', 'Phải tiết kiệm ngân sách khi mua sắm? (EN)', 'Samsung tiếp tục chứng tỏ vị thế của mình tại Việt Nam với loạt sản phẩm bình dân đến cao cấp và họ cũng là nhà sản xuất có nhiều sản phẩm bán chạy nhất tháng 4/2015.', '', '2019-12-19 03:57:24', '2019-12-19 03:57:24'),
(3, 3, 'en', 'Sản phẩm được tin dùng nhất ? (EN)', '', '', '2019-12-19 04:11:07', '2019-12-19 04:11:07'),
(4, 4, 'en', 'Hội thảo công nghệ ? (EN)', '', '', '2019-12-19 04:12:07', '2019-12-19 04:12:22'),
(5, 5, 'en', 'INK REFILLS & PHOTOCHOPY', '', '<div style=\"text-align: center;\"><strong>PRINTING INK SERVICE</strong></div>\n<p style=\"text-align: justify;\"><br />High-quality refilling process must ensure the following:<br /><br />- Clean all print cartridges again<br />- Remove excess ink from the toner before refilling<br />- Handling all components of the cartridge<br />- Use specialized lubricants for ink so that the inside of the cartridge is not subject to strong friction<br />- Check cartridge quality before returning it to customers<br />- Keep track of the number of ink spills on each customer cartridge<br /><br /><br />Results after performing the ink job:<br />- The machine after pouring sharp ink<br />- No ink leakage<br />- Print until the ink runs out and the ink can be spilled again.<br />Technical staff will be available within 45p-60p to resolve the problem.<br /><br /></p>\n<p style=\"text-align: center;\"><strong>\"CUSTOMER SATISFACTION IS A MISSION OF AVP\"</strong></p>', '2019-12-25 03:35:08', '2019-12-25 04:25:33'),
(6, 6, 'en', 'COMPUTERS, PRINTERS MAINTENANCE & WARRANTY', '', '<div style=\"text-align: justify;\"><span style=\"color: #ff0000;\"><strong>The network system operates stably on the infrastructure of existing customers.</strong></span><br /><br /></div>\n<div style=\"text-align: justify;\">* Maintenance 1 time / month according to the job content and the number of machines under the contract<br /><br /></div>\n<div style=\"text-align: justify;\">* Computer problem is handled quickly, take place within 2 hours.<br /><br /></div>\n<div style=\"text-align: justify;\">* Leased machine for replacement, ensure uninterrupted work.<br /><br /></div>\n<div style=\"text-align: justify;\">* Quickly troubleshoot online problems.<br /><br /></div>\n<div style=\"text-align: justify;\">* Guidance for troubleshooting through the phone.<br /><br /></div>\n<div style=\"text-align: justify;\">* Recover lost data.<br /><br /></div>\n<div style=\"text-align: justify;\">* Consulting equipment in the IT field when customers demand.<br /><br /></div>\n<div style=\"text-align: justify;\">* Advice to prevent some common errors.</div>\n<div style=\"text-align: justify;\"><br /><br /><span style=\"color: #ff0000;\"><strong>Content of maintenance:</strong></span><br /><br /><strong>Server maintenance:</strong><br /><br />- Backup data periodically.<br /><br />- Backup mail system.<br /><br />- Monitoring the system, timely handling situations affecting the system.<br /><br />- Building a warning system, monitoring data in and out of computers.<br /><br />- Assign access rights of workstations.<br /><br />- Maintenance of mail system continuously.<br /><br />- Install virus prevention system.<br /><br />- Block, filter software, websites on demand.<br /><br />- Handling hardware and software errors during use.<br /><br />- Diagnose possible problems.<br /><br /><br /><strong>Workstation maintenance:</strong><br /><br />- Optimize the operating speed of the computer. Eliminate unused processes and junk files.<br /><br />- Update virus programs, scan for viruses periodically.<br /><br />- Handling hardware and software errors during use.<br /><br />- Clean the inside of the computer.<br /><br />- Backup periodically data mail, files in the machine.<br /><br />- Diagnose possible problems.</div>', '2019-12-25 04:36:07', '2019-12-25 05:06:41'),
(7, 7, 'en', 'OFFICE MACHINE FOR RENT', '', '<div style=\"text-align: center;\">&gt; Leasing computer (laptop) new life, diverse configuration HP / Dell<br /><br />&gt; For projectors, printers</div>', '2019-12-25 04:46:09', '2020-09-08 02:44:46'),
(8, 8, 'en', 'Rent copiers - Printers', '', 'PRINTER - PHOTO MACHINE LEASE<br />(SUPER SAVING, ULTRA CONVENIENCE)<br /><br /><br />THE SERVICE FOR RENTING, SMOOTH PRINTERS ARE NOT RULES WITH YOU. BUT ON METHOD, PRICE IS ALSO MANY UNreasonable things.<br /><br /><br />Therefore, we have calculated and provided a method for super-convenient and super-saving printers to be smoothed.<br /><br /><br />Super convenient for the following reasons:<br /><br />- NO NEED TO PURCHASE OF MACHINE: Your company does not need to invest in buying a machine but still equips employees with HIGH SPEED PRINTERS - NEW ERRORS.<br /><br />- NO CASH INK: No need to call each cartridge pump for a few tens to hundreds of thousands a box.<br /><br />- NO WAITING FOR: the most convenient, no waiting for the ink pump, because the ink always has spare ink cartridges for you, the speed of the printer we equip for your company is a high-speed, high-speed printer. The level of over 30 printed pages per minute, especially the 2-sided printing technology saves your employees time.<br /><br />- DO NOT LOOSE DAMAGE MACHINE: the machine and ink are ours, you do not need to worry about paying fees for refilling or repairing machines or replacing components. It is our job and our responsibility. When the machine has a problem, we will handle or exchange another device right after 30-60 minutes of receiving the customer\'s notice.<br /><br />SUPER SAVINGS:<br /><br />Only a small calculation will surprise you because of the SUPER SAVING OF our service.<br /><br />QUICK HAND \"Let us serve you\"', '2020-09-08 02:43:40', '2020-09-08 02:43:40'),
(9, 9, 'en', 'Design & Construction of server systems', '', '<div class=\"tlid-input input\">\n<div class=\"source-wrap\">\n<div class=\"input-full-height-wrapper tlid-input-full-height-wrapper\">\n<div class=\"source-input\">\n<div class=\"source-footer-wrap source-or-target-footer\">\n<div class=\"character-count tlid-character-count\">\n<div class=\"cc-ctr normal\">Construction of network infrastructure, projectors, server room</div>\n</div>\n<div class=\"source-footer\">\n<div class=\"speech-wrap source-or-target-footer-button left-positioned\">\n<div id=\"gt-speech\" class=\"speech-button goog-toolbar-button\" aria-label=\"Turn on voice input\" data-tooltip-align=\"t,c\" aria-pressed=\"false\" role=\"button\" aria-disabled=\"false\" data-tooltip=\"Turn on voice input\" tabindex=\"0\"><span class=\"jfk-button-img\"></span></div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>', '2020-09-08 03:05:17', '2020-09-08 03:05:17'),
(10, 10, 'en', 'Design & Construction of camera office-factory', '', 'Construction of camera factory, office', '2020-09-08 03:21:41', '2020-09-08 03:21:41'),
(11, 11, 'en', 'Consulting & designing ERP system (SMB)', '', 'ERP consultant (SMB)', '2020-09-08 03:32:33', '2020-09-08 03:33:05'),
(12, 12, 'en', 'Consulting printing services', '', 'Consulting customers to use the most suitable printer and copier', '2020-09-08 03:38:10', '2020-09-08 03:40:58'),
(13, 13, 'en', 'Website design', '', 'Consulting &amp; designing website as required, package (my name, hositng, ...)', '2020-09-08 03:51:28', '2020-09-08 03:51:28'),
