(1697, 'Thông tin thêm', 'thong-tin-them', '<table id=\"tskt\" style=\"width: 355px; height: 750px; margin-left: auto; margin-right: auto;\">\n<tbody>\n<tr itemprop=\"brand\" itemscope=\"\" itemtype=\"http://schema.org/Brand\" style=\"background-color: #f0f0f0; height: 1px;\">\n<td style=\"width: 329px; text-align: justify; height: 1px;\"><span face=\"arial, helvetica, sans-serif\" style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 16px;\"><b>Th&ocirc;ng s&ocirc;́ kỹ thu&acirc;̣t</b></span></span></td>\n<td style=\"width: 329px; text-align: justify; height: 1px;\"></td>\n</tr>\n<tr style=\"height: 7px;\">\n<td style=\"width: 155px; text-align: justify; height: 7px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Thương hiệu</span></strong></span></td>\n<td style=\"width: 174px; text-align: justify; height: 7px;\"><span face=\"arial, helvetica, sans-serif\" style=\"font-family: arial, helvetica, sans-serif;\">RICOH</span></td>\n</tr>\n<tr style=\"height: 7px;\">\n<td style=\"width: 155px; text-align: justify; height: 7px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Loại</span></strong></span></td>\n<td style=\"width: 174px; height: 7px; text-align: left;\">Laser trắng đen Kỹ thuật số</td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>Đ&ocirc;̣ ph&acirc;n giải</b></span></span></td>\n<td style=\"width: 174px; text-align: justify; height: 1px;\"><span style=\"font-family: arial, helvetica, sans-serif;\">600 dpi</span></td>\n</tr>\n<tr style=\"height: 8px;\">\n<td style=\"width: 155px; height: 8px; text-align: left;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>Thời gian khởi động</b></span></span></td>\n<td style=\"width: 174px; text-align: justify; height: 8px;\"><span face=\"arial, helvetica, sans-serif\" style=\"font-family: arial, helvetica, sans-serif;\">15 gi&acirc;y</span></td>\n</tr>\n<tr style=\"height: 8px;\">\n<td style=\"width: 155px; height: 8px; text-align: left;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>C&ocirc;ng suất trung b&igrave;nh</b></span></span></td>\n<td style=\"width: 174px; height: 8px; text-align: left;\">50.000 bản/ th&aacute;ng</td>\n</tr>\n<tr style=\"height: 8px;\">\n<td style=\"width: 155px; text-align: justify; height: 8px;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>Số bản chụp tối đa</b></span></span></td>\n<td style=\"width: 174px; height: 8px; text-align: left;\">999 tờ</td>\n</tr>\n<tr style=\"height: 8px;\">\n<td style=\"width: 155px; text-align: justify; height: 8px;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>Khay giấy chuẩn</b></span></span></td>\n<td style=\"width: 174px; height: 8px; text-align: left;\">2&times;500+100 by pass</td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>H&ecirc;̣ đi&ecirc;̀u hành h&ocirc;̃ trợ</b></span></span></td>\n<td style=\"width: 174px; height: 1px;\">\n<div style=\"text-align: left;\"><span style=\"font-family: arial, helvetica, sans-serif;\">Windows 7;8.1;10.</span></div>\n</td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>C&acirc;n nặng<br /></b></span></span></td>\n<td style=\"width: 174px; height: 1px;\">\n<div style=\"text-align: left;\"><span style=\"font-family: arial, helvetica, sans-serif;\">97kg<br /></span></div>\n</td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>K&iacute;ch thước</b></span></span></td>\n<td style=\"width: 174px; height: 1px;\">670 x 682 x 895 mm</td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>Nguồn điện</b></span></span></td>\n<td style=\"width: 174px; height: 1px;\">120 volts 20Amps.1.85KW</td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>Hệ điều h&agrave;nh</b></span></span></td>\n<td style=\"width: 174px; height: 1px;\">Windows&reg; XP, Windows&reg; Vista, Windows&reg;7, Windows&reg; Server 2003, Windows&reg;Server 2008, Windows&reg; Server 2008R2</td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>Giao thức</b></span></span></td>\n<td style=\"width: 174px; height: 1px;\">TCP/IP (IP v4, IP v6), IPX/SPX</td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; height: 1px; text-align: left;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>Tuổi thọ Drum trung b&igrave;nh</b></span></span></td>\n<td style=\"width: 174px; height: 1px;\">&nbsp;600.000 trang</td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span color=\"#999999\" face=\"arial, helvetica, sans-serif\" style=\"color: #999999; font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\"><b>Hộp mực</b></span></span></td>\n<td style=\"width: 174px; height: 1px;\">20.000 trang (độ phủ mực 5%)</td>\n</tr>\n</tbody>\n</table>', 87, 'product', '2020-04-26 20:42:57', '2020-04-27 02:37:31'),
