(2023, 'Thông tin thêm', 'thong-tin-them', '<table id=\"tskt\" style=\"height: 520px; width: 345px; margin-left: auto; margin-right: auto;\">\n<tbody>\n<tr itemprop=\"brand\" itemscope=\"\" itemtype=\"http://schema.org/Brand\" style=\"background-color: #f0f0f0; height: 1px; text-align: left;\">\n<td style=\"width: 329px; text-align: justify; height: 1px;\"><span face=\"georgia, palatino, serif\" style=\"font-family: arial, helvetica, sans-serif; font-size: 12pt;\"><b>C&acirc;́u hình chi ti&ecirc;́t</b></span></td>\n<td style=\"width: 329px; text-align: justify; height: 1px;\"></td>\n</tr>\n<tr style=\"height: 1px; text-align: left;\">\n<td style=\"width: 155px; height: 1px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Thương hiệu</span></strong></span></td>\n<td style=\"width: 174px; text-align: justify; height: 1px;\"><span face=\"arial, helvetica, sans-serif\" style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\">OKI</span></span></td>\n</tr>\n<tr style=\"height: 3px; text-align: left;\">\n<td style=\"width: 155px; height: 3px; text-align: left;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt; color: #999999;\">Bảo h&agrave;nh</span></strong></td>\n<td style=\"width: 174px; height: 3px; text-align: left;\">1 năm</td>\n</tr>\n<tr style=\"height: 1px; text-align: left;\">\n<td style=\"width: 155px; height: 1px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Độ ph&acirc;n giải</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\">360 x 360dpi</td>\n</tr>\n<tr style=\"height: 1px; text-align: left;\">\n<td style=\"width: 155px; height: 1px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Bộ nhớ</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\">Bộ nhớ đệm 128KB</td>\n</tr>\n<tr style=\"height: 2px; text-align: left;\">\n<td style=\"width: 155px; height: 2px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Tốc độ in</span></strong></span></td>\n<td style=\"width: 174px; text-align: justify; height: 2px;\">\n<p style=\"text-align: left;\">l&ecirc;n đến 333 k&yacute; tự tr&ecirc;n gi&acirc;y, khả năng in được 1 bản gốc + 4 bản copy</p>\n</td>\n</tr>\n<tr style=\"height: 2px; text-align: left;\">\n<td style=\"width: 155px; height: 2px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">C&ocirc;ng nghệ</span></strong></span></td>\n<td style=\"width: 174px; text-align: justify; height: 2px;\">\n<p style=\"text-align: left;\">C&oacute; thể in 5 bản (1 bản ch&iacute;nh v&agrave; 4 bản sao), sử dụng 24 kim in, tuổi thọ đầu kim 200 triệu k&iacute; tự, tuổi thọ băng mực 4 triệu k&iacute; tự, c&ocirc;ng suất in 10.000 giờ</p>\n</td>\n</tr>\n<tr style=\"height: 1px; text-align: left;\">\n<td style=\"width: 155px; height: 1px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Nguồn điện</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\">Điện &aacute;p đầu v&agrave;o 2V-240 VAC, tần số 50/60 Hz</td>\n</tr>\n<tr style=\"height: 14px; text-align: left;\">\n<td style=\"width: 155px; height: 14px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Hệ điều h&agrave;nh</span></strong></span></td>\n<td style=\"width: 174px; height: 14px; text-align: left;\">Microsoft&reg; Windows&reg; 2000 / XP / 7, Microsoft&reg; Windows Vista&reg;</td>\n</tr>\n<tr style=\"height: 1px; text-align: left;\">\n<td style=\"width: 155px; height: 1px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Kết nối</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\">Parrallel, USB 2.0, Serial RS-232</td>\n</tr>\n<tr style=\"height: 4px;\">\n<td style=\"width: 155px; height: 4px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">M&atilde; mực in</span></strong></span></td>\n<td style=\"width: 174px; height: 4px; text-align: left;\">Ribbon Oki ML-1120/1190 (4 tri&ecirc;̣u ký tự)</td>\n</tr>\n<tr style=\"height: 3px;\">\n<td style=\"width: 155px; text-align: justify; height: 3px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Th&ocirc;ng tin giấy in</span></strong></span></td>\n<td style=\"width: 174px; text-align: justify; height: 3px;\">\n<p style=\"text-align: left;\">Giấy li&ecirc;n tục ngang: 76.2 - 245 mm, giấy ti&ecirc;u chuẩn A4 (210 x 297 mm), A5 (148 x 210 mm), tự động cuốn giấy, tự động định vị đầu kim</p>\n</td>\n</tr>\n<tr style=\"height: 2px;\">\n<td style=\"width: 155px; height: 2px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">K&iacute;ch thước</span></strong></span></td>\n<td style=\"width: 174px; height: 2px; text-align: left;\">150 x 349 x 232 mm</td>\n</tr>\n<tr style=\"height: 2px;\">\n<td style=\"width: 155px; height: 2px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Trọng lượng</span></strong></span></td>\n<td style=\"width: 174px; height: 2px; text-align: left;\">4.2000</td>\n</tr>\n</tbody>\n</table>', 104, 'product', '2020-04-27 19:20:03', '2020-04-27 20:11:36'),
