(1506, 1793, 'en', '<div style=\"text-align: justify;\"><strong>Th&ocirc;ng s&ocirc;́ kỹ thu&acirc;̣t</strong></div>\n<div>\n<ul style=\"text-align: justify;\">\n<li><strong>T&ecirc;n sản ph&acirc;̉m</strong>: M&aacute;y Chiếu Epson EB-2042</li>\n<li><strong>Thương hi&ecirc;̣u</strong>: Espon&nbsp;</li>\n<li><strong>C&ocirc;ng nghệ:</strong> 3LCD Technology, RGB liquid crystal shutter</li>\n<li><strong>Độ s&aacute;ng:</strong> 4,400 Ansi Lumens</li>\n<li><strong>Độ ph&acirc;n giải:</strong> XGA (1,024 x 786)</li>\n<li><strong>M&agrave;u sắc hiển thị:</strong> 1.07 tỉ m&agrave;u</li>\n<li><strong>Độ tương phản:</strong> 15,000:1</li>\n<li><strong>B&oacute;ng đ&egrave;n:</strong> 230W UHE</li>\n<li><strong>Tỉ lệ chiếu:</strong> 4:3</li>\n<li><strong>Chỉnh vu&ocirc;ng h&igrave;nh theo chiều dọc:</strong> Tự động c&acirc;n chỉnh chiều dọc h&igrave;nh ảnh</li>\n<li><strong>K&iacute;ch thước tr&igrave;nh chiếu:</strong> 1.69m - 2.75m ( 60 inch screen)</li>\n<li><strong>Tuổi thọ b&oacute;ng đ&egrave;n:</strong> 5,500 giờ</li>\n<li><strong>Cổng kết nối:</strong> 2x VGA in/ 2x HDMI in</li>\n<li><strong>C&ocirc;ng xuất loa:</strong> 16W</li>\n<li><strong>T&iacute;nh năng đặc biệt:</strong> Nắp A/V mute tạm dừng tr&igrave;nh chiếu, tiết kiệm điện năng</li>\n<li><strong>Cổng USB-B:</strong> (3 trong 1) tr&igrave;nh chiếu h&igrave;nh ảnh, &acirc;m thanh v&agrave; điều khiển từ xa</li>\n<li><strong>Khởi động:</strong> trong 8 gi&acirc;y v&agrave; tắt m&aacute;y nhanh (Quick start and instant off)</li>\n<li><strong>K&iacute;nh thước:</strong> 380 x 300 x 100 mm</li>\n<li><strong>Trọng lượng:</strong> 4,4 kg</li>\n<li><strong>Bảo h&agrave;nh:</strong> Ch&iacute;nh h&atilde;ng</li>\n</ul>\n</div>', '2020-04-27 02:45:25', '2020-04-27 05:30:13'),
