(1618, 1928, 'en', '<table id=\"tskt\" style=\"height: 520px; width: 345px; margin-left: auto; margin-right: auto;\">\n<tbody>\n<tr itemprop=\"brand\" itemscope=\"\" itemtype=\"http://schema.org/Brand\" style=\"background-color: #f0f0f0; height: 1px; text-align: left;\">\n<td style=\"width: 329px; text-align: justify; height: 1px;\"><span face=\"georgia, palatino, serif\" style=\"font-family: arial, helvetica, sans-serif; font-size: 12pt;\"><b>C&acirc;́u hình chi ti&ecirc;́t</b></span></td>\n<td style=\"width: 329px; text-align: justify; height: 1px;\"></td>\n</tr>\n<tr style=\"height: 1px; text-align: left;\">\n<td style=\"width: 155px; height: 1px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Thương hiệu</span></strong></span></td>\n<td style=\"width: 174px; text-align: justify; height: 1px;\"><span face=\"arial, helvetica, sans-serif\" style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\">BROTHER</span></span></td>\n</tr>\n<tr style=\"height: 3px; text-align: left;\">\n<td style=\"width: 155px; height: 3px; text-align: left;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt; color: #999999;\">Chức năng</span></strong></td>\n<td style=\"width: 174px; height: 3px; text-align: left;\">ENERGY STAR&reg; certified</td>\n</tr>\n<tr style=\"height: 1px; text-align: left;\">\n<td style=\"width: 155px; height: 1px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Độ ph&acirc;n giải</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\">180 x 360 dpi</td>\n</tr>\n<tr style=\"height: 8px; text-align: left;\">\n<td style=\"width: 155px; height: 8px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Tốc độ in</span></strong></span></td>\n<td style=\"width: 174px; text-align: justify; height: 8px;\">\n<p style=\"text-align: left;\">up to 30mm/sec. (using AC adapter); up to 20mm/sec. (using batteries)</p>\n</td>\n</tr>\n<tr style=\"height: 1px; text-align: left;\">\n<td style=\"width: 155px; height: 1px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">C&ocirc;ng nghệ</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\">Print Black/ Dark Gray. Keyboard: QWERTY</td>\n</tr>\n<tr style=\"height: 14px; text-align: left;\">\n<td style=\"width: 155px; height: 14px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Hệ điều h&agrave;nh</span></strong></span></td>\n<td style=\"width: 174px; height: 14px; text-align: left;\">Windows&reg; 10; Windows&reg; 8/8.1, Windows&reg; 7; Windows Vista&reg; Mac OS X 10.7.5, 10.8.x, 10.9.x, 10.10.x</td>\n</tr>\n<tr style=\"height: 1px; text-align: left;\">\n<td style=\"width: 155px; height: 1px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Khổ giấy</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\">Size 3.5mm, 6mm, 9mm, 12mm, 18mm, 24mm</td>\n</tr>\n<tr style=\"height: 4px;\">\n<td style=\"width: 155px; height: 4px; text-align: left;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">M&agrave;n h&igrave;nh hiển thị</span></strong></span></td>\n<td style=\"width: 174px; height: 4px; text-align: left;\">20-char. x 3 line Full-color Display with Backlight</td>\n</tr>\n<tr style=\"height: 3px;\">\n<td style=\"width: 155px; text-align: justify; height: 3px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">K&iac