(1762, 2100, 'en', '<table id=\"tskt\" style=\"height: 525px; width: 345px; margin-left: auto; margin-right: auto;\">\n<tbody>\n<tr itemprop=\"brand\" itemscope=\"\" itemtype=\"http://schema.org/Brand\" style=\"background-color: #f0f0f0; height: 1px;\">\n<td style=\"width: 329px; height: 1px; text-align: left;\"><span face=\"arial, helvetica, sans-serif\" style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 16px;\"><b>Th&ocirc;ng s&ocirc;́ kỹ thu&acirc;̣t</b></span></span></td>\n<td style=\"width: 329px; text-align: justify; height: 1px;\"></td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Thương hiệu</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\"><span face=\"arial, helvetica, sans-serif\" style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\">ACER</span></span></td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Bảo h&agrave;nh<br /></span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\"><span face=\"arial, helvetica, sans-serif\" style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\">12 th&aacute;ng<br /></span></span></td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Series laptop</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\"><span face=\"arial, helvetica, sans-serif\" style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-size: 14.6667px;\">Aspire E5</span></span></td>\n</tr>\n<tr style=\"height: 3px;\">\n<td style=\"width: 155px; text-align: justify; height: 3px;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt; color: #999999;\">Part-number</span></strong></td>\n<td style=\"width: 174px; height: 3px; text-align: left;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">NX.GRDSV.001</span></td>\n</tr>\n<tr style=\"height: 3px;\">\n<td style=\"width: 155px; text-align: justify; height: 3px;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt; color: #999999;\">Màn hình</span></strong></td>\n<td style=\"width: 174px; height: 3px; text-align: left;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">14\" ( 1920 x 1080 ) Full HD kh&ocirc;ng cảm ứng. M&agrave;n h&igrave;nh chống l&oacute;a, HD webcam</span></td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">CPU</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\">Intel Core i5-8250U ( 1.6 GHz - 3.4 GHz / 6MB / 4 nh&acirc;n, 8 lu&ocirc;̀ng )</td>\n</tr>\n<tr style=\"height: 8px;\">\n<td style=\"width: 155px; text-align: justify; height: 8px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Th&ecirc;́ h&ecirc;̣ CPU</span></strong></span></td>\n<td style=\"width: 174px; height: 8px; text-align: left;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Intel Core th&ecirc;́ h&ecirc;̣ thứ 8</span></td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">RAM</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\">1 x 4GB DDR4 2400MHz ( 2 Khe cắm / Hỗ trợ tối đa 32GB )</td>\n</tr>\n<tr style=\"height: 14px;\">\n<td style=\"width: 155px; text-align: justify; height: 14px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Chip đ&ocirc;̀ họa</span></strong></span></td>\n<td style=\"width: 174px; height: 14px; text-align: left;\">Intel UHD Graphics 620</td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Lưu trữ</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\">1TB HDD 5400RPM</td>\n</tr>\n<tr style=\"height: 4px;\">\n<td style=\"width: 155px; text-align: justify; height: 4px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">S&ocirc;́ c&ocirc;̉ng lưu trữ t&ocirc;́i đa</span></strong></span></td>\n<td style=\"width: 174px; height: 4px; text-align: left;\">1 x 2.5\" SATA, 1 x M.2 SATA/NVMe</td>\n</tr>\n<tr style=\"height: 3px;\">\n<td style=\"width: 155px; text-align: justify; height: 3px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Kiểu khe M.2 hỗ trợ</span></strong></span></td>\n<td style=\"width: 174px; height: 3px; text-align: left;\">M.2 SATA/NVMe</td>\n</tr>\n<tr style=\"height: 2px;\">\n<td style=\"width: 155px; text-align: justify; height: 2px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">C&ocirc;̉ng xu&acirc;́t hình</span></strong></span></td>\n<td style=\"width: 174px; height: 2px; text-align: left;\">1 x HDMI, 1 x VGA/D-sub</td>\n</tr>\n<tr style=\"height: 1px;\">\n<td style=\"width: 155px; text-align: justify; height: 1px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Cổng kết nối</span></strong></span></td>\n<td style=\"width: 174px; height: 1px; text-align: left;\">2 x USB 3.0 , 1 x USB 2.0 , 1 x SD card slot, LAN 1 Gb/s</td>\n</tr>\n<tr style=\"height: 20px;\">\n<td style=\"width: 155px; text-align: justify; height: 20px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">B&ocirc;̣ nhớ h&ocirc;̃ trợ</span></strong></span></td>\n<td style=\"width: 174px; height: 20px; text-align: left;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">DDR4 Dual channel</span></td>\n</tr>\n<tr style=\"height: 20px;\">\n<td style=\"width: 155px; text-align: justify; height: 20px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">K&ecirc;́t n&ocirc;́i kh&ocirc;ng d&acirc;y</span></strong></span></td>\n<td style=\"width: 174px; height: 20px; text-align: left;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">WiFi 802.11ac, Bluetooth 4.2</span></td>\n</tr>\n<tr style=\"height: 20px;\">\n<td style=\"width: 155px; text-align: justify; height: 20px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Bàn phím</span></strong></span></td>\n<td style=\"width: 174px; height: 20px; text-align: left;\">thường, kh&ocirc;ng phím s&ocirc;́, kh&ocirc;ng đèn</td>\n</tr>\n<tr style=\"height: 20px;\">\n<td style=\"width: 155px; text-align: justify; height: 20px;\"><span style=\"color: #999999;\"><strong><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">H&ecirc;̣ đi&ecirc;̀u hành</span></strong></span></td>\n<td style=\"width: 174px; height: 20px; text-align: left;\">Linux</td>\n</tr>\n<tr style=\"height: 20px;\">\n<td style=\"width: 155px; text-align: justify; height: 20px;\"><strong><span style=\"color: #999999;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Kích thước</span></span></strong></td>\n<td style=\"width: 174px; height: 20px; text-align: left;\">34.3 x 24.8 x 3 cm</td>\n</tr>\n<tr style=\"height: 20px;\">\n<td style=\"width: 155px; text-align: justify; height: 20px;\"><strong><span style=\"color: #999999;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Pin</span></span></strong></td>\n<td style=\"width: 174px; height: 20px; text-align: left;\">4 cell 41 Wh, Pin liền</td>\n</tr>\n<tr style=\"height: 20px;\">\n<td style=\"width: 155px; text-align: justify; height: 20px;\"><strong><span style=\"color: #999999;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Kh&ocirc;́i lượng</span></span></strong></td>\n<td style=\"width: 174px; height: 20px; text-align: left;\">2 kg</td>\n</tr>\n<tr style=\"height: 20px;\">\n<td style=\"width: 155px; text-align: justify; height: 20px;\"><strong><span style=\"color: #999999;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Ổ đĩa quang</span></span></strong></td>\n<td style=\"width: 174px; height: 20px; text-align: left;\">DVD/CD RW</td>\n</tr>\n<tr style=\"height: 20px;\">\n<td style=\"width: 155px; text-align: justify; height: 20px;\"><strong><span style=\"color: #999999;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 11pt;\">Đ&egrave;n LED tr&ecirc;n m&aacute;y<br /></span></span></strong></td>\n<td style=\"width: 174px; height: 20px; text-align: left;\">kh&ocirc;ng đèn</td>\n</tr>\n</tbody>\n</table>', '2020-04-28 07:19:35', '2020-04-28 09:06:17'),
