(1, 1, 'Tai nghe nhạc Kingston', '<span>Cảm nhận chi tiết đến từng &acirc;m thanh h&ograve;a lẫn v&agrave;o trong &acirc;m nhạc. Sản phẩm mới chất lượng cao nhất hiện nay.</span>', 'home-shop-slider-1_1576661364.jpg', '', 'custom', '', 'inactive', 0, '2019-12-19 03:18:42', '2020-01-15 03:11:11'),
(2, 1, 'Ghế văn phòng thế hệ mới', '<span>Với thiết kế tinh tế theo kịp xu hướng văn ph&ograve;ng hiện nay, ghế ngồi DACXS25 mang đến sự thoải m&aacute;i trong c&ocirc;ng việc.</span>', 'home-shop-slider-3_1576661363.jpg', '', 'custom', '', 'inactive', 1, '2019-12-19 03:20:45', '2020-01-15 03:11:11'),
(3, 1, 'Đồng hồ thông minh nhãn hiệu Popact', '<span>C&ugrave;ng trải nghiệm c&ocirc;ng nghệ mới c&ugrave;ng Papact Watch. T&iacute;ch hợp nhiều nhiều t&iacute;nh năng: lướt web, điện thoại, nhắn tin,...</span>', 'home-shop-slider-21_1576661364.jpg', '', 'custom', '', 'inactive', 2, '2019-12-19 03:21:55', '2020-01-15 03:11:11'),
