(9, 3, 'AVP luôn luôn đồng hành cùng Quý khách hàng', 'Thường xuy&ecirc;n c&oacute; c&aacute;c chương tr&igrave;nh khuyến mại hấp dẫn &amp; bất ngờ, mang sự h&agrave;i l&ograve;ng đến kh&aacute;ch h&agrave;ng', 'tantinh_1577238861.jpg', '', 'custom', '', 'active', 0, '2019-12-19 08:28:54', '2019-12-25 02:08:34'),
(10, 3, 'Đội ngũ AVP phục vụ khách hàng tận tâm & nhanh chóng', 'Mực AVP: Bảo h&agrave;nh đến \"giọt mực cuối c&ugrave;ng\".&nbsp;Hỗ trợ vệ sinh m&aacute;y in miễn ph&iacute; định kỳ', 'business-people-shaking-hands-together_53876-30568_1577239270.jpg', '', 'custom', '', 'active', 1, '2019-12-19 08:29:35', '2019-12-25 02:09:30'),
