INSERT INTO `product` (`id`, `title`, `image`, `description`, `content`, `sell`, `view`, `rating`, `status`, `priority`, `tags`, `template`, `stock_manage`, `stop_selling`, `stock_quant`, `option_1`, `option_2`, `option_3`, `option_4`, `option_5`, `option_6`, `created_at`, `updated_at`, `raw_title`, `raw_full`) VALUES
(1, 'Đồng hồ đeo tay App Watch', 's-digital-app-watch-600x600_1576661368.jpg', 'Được sản xuất độc quyền tại Mỹ, đồng hồ App Watch mang lại sự lịch lãm và sang trọng cho khách hàng quý phái. Được sự đánh giá cao từ giới chuyên môn App Watch dần khẳng định được tên tuổi của mình trên thị trường thế giới.', '<h6>Thiết kế đồng hồ Apple Watch.</h6>\n<p>Đồng hồ App Watch c&oacute; thiết kế Unibody nguy&ecirc;n khối, chất liệu bằng th&eacute;p kh&ocirc;ng gỉ, nh&ocirc;m, hoặc v&agrave;ng 18 karat t&ugrave;y phi&ecirc;n bản kh&aacute;c nhau. Mặt đồng hồ c&oacute; kiểu d&aacute;ng chữ nhật bo tr&ograve;n v&agrave; l&agrave;m bằng chất liệu sapphire chống va đập, chống xước cao cấp. Bạn c&oacute; hai k&iacute;ch thước mặt đồng hồ để lựa chọn l&agrave; 38mm v&agrave; 42mm. Với cổ tay b&igrave;nh thường người Việt Nam th&igrave; 38mm c&oacute; lẽ l&agrave; hợp l&yacute; hơn. Apple Watch c&oacute; khả năng chống nước v&agrave; 6 lựa chọn d&acirc;y đeo kh&aacute;c nhau</p>\n<br />\n<h6>C&aacute;c phi&ecirc;n bản đồng hồ App Watch</h6>\n<p>App Watch mang đến cho người d&ugrave;ng rất nhiều lựa chọn khi ngo&agrave;i việc c&oacute; hai k&iacute;ch thước m&agrave;n h&igrave;nh l&agrave; 38mm v&agrave; 42mm, chiếc đồng hồ n&agrave;y c&oacute; ba phi&ecirc;n bản chất liệu kh&aacute;c nhau c&ugrave;ng nhiều lựa chọn d&acirc;y đeo. Do đ&oacute; bạn sẽ c&oacute; h&agrave;ng chục phi&ecirc;n bản kh&aacute;c nhau để lựa chọn. Để người d&ugrave;ng tiện ph&acirc;n biệt, Apple đ&atilde; chia đồng hồ Apple Watch th&agrave;nh ba nh&oacute;m ch&iacute;nh: App Watch, App Watch Sport, App Watch Edition</p>\n<br />\n<h6>T&iacute;nh năng của đồng hồ App Watch</h6>\n<p>Nhắn tin, C&aacute; nh&acirc;n h&oacute;a h&igrave;nh ảnh, Digital Touch, Gọi điện, Siri, Bản đồ, nghe nhạc,...</p>', 0, 378, 0.00, 'inactive', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2019-12-19 02:54:42', '2020-04-15 02:04:26', 'dong ho deo tay app watch', 'dong ho deo tay app watch duoc san xuat doc quyen tai my, dong ho app watch mang lai su lich lam va sang trong cho khach hang quy phai. duoc su danh gia cao tu gioi chuyen mon app watch dan khang dinh duoc ten tuoi cua minh tren thi truong the gioi. thiet ke dong ho apple watch. dong ho app watch c&oacute; thiet ke unibody nguy&ecirc;n khoi, chat lieu bang th&eacute;p kh&ocirc;ng gi, nh&ocirc;m, hoac v&agrave;ng 18 karat t&ugrave;y phi&ecirc;n ban kh&aacute;c nhau. mat dong ho c&oacute; kieu d&aacute;ng chu nhat bo tr&ograve;n v&agrave; l&agrave;m bang chat lieu sapphire chong va dap, chong xuoc cao cap. ban c&oacute; hai k&iacute;ch thuoc mat dong ho de lua chon l&agrave; 38mm v&agrave; 42mm. voi co tay b&igrave;nh thuong nguoi viet nam th&igrave; 38mm c&oacute; le l&agrave; hop l&yacute; hon. apple watch c&oacute; kha nang chong nuoc v&agrave; 6 lua chon d&acirc;y deo kh&aacute;c nhau c&aacute;c phi&ecirc;n ban dong ho app watch app watch mang den cho nguoi d&ugrave;ng rat nhieu lua chon khi ngo&agrave;i viec c&oacute; hai k&iacute;ch thuoc m&agrave;n h&igrave;nh l&agrave; 38mm v&agrave; 42mm, chiec dong ho n&agrave;y c&oacute; ba phi&ecirc;n ban chat lieu kh&aacute;c nhau c&ugrave;ng nhieu lua chon d&acirc;y deo. do d&oacute; ban se c&oacute; h&agrave;ng chuc phi&ecirc;n ban kh&aacute;c nhau de lua chon. de nguoi d&ugrave;ng tien ph&acirc;n biet, apple d&atilde; chia dong ho apple watch th&agrave;nh ba nh&oacute;m ch&iacute;nh: app watch, app watch sport, app watch edition t&iacute;nh nang cua dong ho app watch nhan tin, c&aacute; nh&acirc;n h&oacute;a h&igrave;nh anh, digital touch, goi dien, siri, ban do, nghe nhac,...'),
