(86, 'Máy Fax Brother', 'may-fax-lazer-brother-2840_1587917909.jpg', '', '<strong>M&aacute;y Fax Brother</strong><br />\n<ul>\n<li>Thương hi&ecirc;̣u:&nbsp;Panasonic, Brother</li>\n<li>Thi&ecirc;́t k&ecirc;́ gọn gàng d&ecirc;̃ dàng b&ocirc;́ trí trong văn phòng.</li>\n</ul>', 0, 1736, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-26 16:07:21', '2020-04-26 21:43:03', 'may fax brother', 'may fax brother m&aacute;y fax brother thuong hi&ecirc;̣u:&nbsp;panasonic, brother thi&ecirc;́t k&ecirc;́ gọn gàng d&ecirc;̃ dàng b&ocirc;́ trí trong van phòng. '),
(87, 'Máy photocopy Ricoh', 'may-photocopy-ricoh-mp-4002-5002_1587933170.jpg', '', '<strong>M&aacute;y photocopy Ricoh MP 5002</strong><br />- <strong>Ricoh MP 5002</strong> được đ&aacute;nh gi&aacute; l&agrave; một trong những thiết bị m&aacute;y photocopy đa chức năng A3 tốt nhất cho văn ph&ograve;ng. M&aacute;y đ&aacute;p ứng đầy đủ những yếu tố cần của một thiết bị in tốt: đa chức năng, tốc độ cao, bền v&agrave; chất lượng bản in đẹp.<br />- <strong>Th&ocirc;ng số ch&iacute;nh</strong><br />\n<ul>\n<li>Chức năng Photocopy - Print - Scan m&agrave;u</li>\n<li>Tốc độ in 50 bản/ph&uacute;t</li>\n<li>Khởi động 15 gi&acirc;y</li>\n<li>Khay giấy chuẩn 1100 tờ</li>\n<li>Bộ nhớ 1GB + 128GB HDD</li>\n<li>C&acirc;n nặng 97 kg</li>\n<li>Tỉ lệ thu ph&oacute;ng 25-400%</li>\n</ul>', 0, 2054, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-26 20:42:56', '2020-04-27 02:37:29', 'may photocopy ricoh', 'may photocopy ricoh m&aacute;y photocopy ricoh mp 5002- ricoh mp 5002 duoc d&aacute;nh gi&aacute; l&agrave; mot trong nhung thiet bi m&aacute;y photocopy da chuc nang a3 tot nhat cho van ph&ograve;ng. m&aacute;y d&aacute;p ung day du nhung yeu to can cua mot thiet bi in tot: da chuc nang, toc do cao, ben v&agrave; chat luong ban in dep.- th&ocirc;ng so ch&iacute;nh chuc nang photocopy - print - scan m&agrave;u toc do in 50 ban/ph&uacute;t khoi dong 15 gi&acirc;y khay giay chuan 1100 to bo nho 1gb + 128gb hdd c&acirc;n nang 97 kg ti le thu ph&oacute;ng 25-400% '),
(88, 'Máy photocopy Xerox/ Canon/ Tohiba/ Minolta Konica', 'may-photocopy-xerox_1587936763.jpg', '', '<strong>M&aacute;y photocopy Xerox/ Canon/ Tohiba/ Minolta Konica<br /></strong>\n<ul>\n<li>Thương hi&ecirc;̣u: Xerox, Canon, Tohiba, Minolta Konica</li>\n<li>Đ&ocirc;̣ b&ecirc;̀n cao</li>\n<li>Chất lượng bản in đẹp.</li>\n</ul>', 0, 1570, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-26 21:33:38', '2020-04-26 21:39:40', 'may photocopy xerox/ canon/ tohiba/ minolta konica', 'may photocopy xerox/ canon/ tohiba/ minolta konica m&aacute;y photocopy xerox/ canon/ tohiba/ minolta konica thuong hi&ecirc;̣u: xerox, canon, tohiba, minolta konica d&ocirc;̣ b&ecirc;̀n cao chat luong ban in dep. '),
(89, 'Máy scan HP', 'may-scan-hp_1587940422.jpg', '', '<strong>M&aacute;y scan HP</strong><br />\n<ul>\n<li>Thương hi&ecirc;̣u: HP</li>\n<li>Thi&ecirc;́t k&ecirc;́ gọn gàng d&ecirc;̃ dàng b&ocirc;́ trí trong văn phòng.</li>\n<li>Ch&acirc;́t&nbsp; lượng bản scan sắc nét</li>\n</ul>', 0, 2110, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-26 22:34:31', '2020-04-27 01:16:58', 'may scan hp', 'may scan hp m&aacute;y scan hp thuong hi&ecirc;̣u: hp thi&ecirc;́t k&ecirc;́ gọn gàng d&ecirc;̃ dàng b&ocirc;́ trí trong van phòng. ch&acirc;́t&nbsp; luọng bản scan sác nét '),
(90, 'Máy scan Epson', 'may-scan-espon-01_1587950430.jpg', '', '<strong>M&aacute;y scan&nbsp;Epson</strong><br />\n<ul>\n<li>Thương hi&ecirc;̣u:&nbsp;Epson</li>\n<li>Thi&ecirc;́t k&ecirc;́ gọn gàng d&ecirc;̃ dàng b&ocirc;́ trí trong văn phòng.</li>\n<li>Ch&acirc;́t&nbsp; lượng bản scan sắc nét</li>\n</ul>', 0, 2060, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 01:18:47', '2020-04-27 01:24:17', 'may scan epson', 'may scan epson m&aacute;y scan&nbsp;epson thuong hi&ecirc;̣u:&nbsp;epson thi&ecirc;́t k&ecirc;́ gọn gàng d&ecirc;̃ dàng b&ocirc;́ trí trong van phòng. ch&acirc;́t&nbsp; luọng bản scan sác nét '),
(91, 'Máy scan Fujitsu', 'may-scan-fujitsu_1587951856.jpg', '', '<strong>M&aacute;y scan&nbsp;Fujitsu</strong><br />\n<ul>\n<li>Thương hi&ecirc;̣u:&nbsp;Fujitsu</li>\n<li>Thi&ecirc;́t k&ecirc;́ gọn gàng, d&ecirc;̃ dàng b&ocirc;́ trí trong văn phòng.</li>\n<li>Ch&acirc;́t&nbsp; lượng bản scan sắc nét</li>\n</ul>', 0, 1718, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 01:41:17', '2020-04-27 02:16:21', 'may scan fujitsu', 'may scan fujitsu m&aacute;y scan&nbsp;fujitsu thuong hi&ecirc;̣u:&nbsp;fujitsu thi&ecirc;́t k&ecirc;́ gọn gàng, d&ecirc;̃ dàng b&ocirc;́ trí trong van phòng. ch&acirc;́t&nbsp; luọng bản scan sác nét '),
(92, 'Máy chiếu Epson', 'may-chieu-epson-eb-2042-1_1587957130.jpg', '', '<strong>M&aacute;y chiếu Epson</strong>\n<div style=\"text-align: justify;\">- M&aacute;y chiếu Epson EB-2042 sở hữu những t&iacute;nh năng tuyệt vời v&agrave; hiệu suất l&agrave;m việc cao với 3LCD, c&ugrave;ng độ s&aacute;ng l&ecirc;n đến 4400 Ansi Lumens. Dễ d&agrave;ng thiết lập v&agrave; c&aacute;c t&iacute;nh năng kết nối l&agrave;m cho n&oacute; đơn giản để hiển thị nội dung một c&aacute;ch nhanh ch&oacute;ng. Epson EB-2042 c&oacute; thể tr&igrave;nh chiếu tốt nhất ngay cả khi ph&ograve;ng c&oacute; nhiều s&aacute;ng.</div>\n- <strong>Tính năng n&ocirc;̉i b&acirc;̣t:</strong><br />\n<ul>\n<li>Cường độ s&aacute;ng trắng: 4,400 Ansi Lumens</li>\n<li>Cường độ s&aacute;ng m&agrave;u: 4,400 Ansi Lumens</li>\n<li>Độ ph&acirc;n giải thực: XGA (1024 x 768)</li>\n<li>Độ tương phản: 15.000:1</li>\n<li>B&oacute;ng đ&egrave;n: Tuổi thọ 10,000 giờ</li>\n<li>Loa &acirc;m thanh : 16W</li>\n<li>Chiếu lệch g&oacute;c: +/-30 độ (dọc, ngang)</li>\n<li>Tr&igrave;nh chiếu h&igrave;nh ảnh từ USB</li>\n<li>Tr&igrave;nh chiếu v&agrave; quản l&yacute; m&aacute;y chiếu th&ocirc;ng qua mạng LAN</li>\n<li>Cổng USB-B (3 trong 1) tr&igrave;nh chiếu h&igrave;nh ảnh, &acirc;m</li>\n</ul>', 0, 2083, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 02:45:24', '2020-04-27 05:30:12', 'may chieu epson', 'may chieu epson m&aacute;y chieu epson - m&aacute;y chieu epson eb-2042 so huu nhung t&iacute;nh nang tuyet voi v&agrave; hieu suat l&agrave;m viec cao voi 3lcd, c&ugrave;ng do s&aacute;ng l&ecirc;n den 4400 ansi lumens. de d&agrave;ng thiet lap v&agrave; c&aacute;c t&iacute;nh nang ket noi l&agrave;m cho n&oacute; don gian de hien thi noi dung mot c&aacute;ch nhanh ch&oacute;ng. epson eb-2042 c&oacute; the tr&igrave;nh chieu tot nhat ngay ca khi ph&ograve;ng c&oacute; nhieu s&aacute;ng. - tính nang n&ocirc;̉i b&acirc;̣t: cuong do s&aacute;ng trang: 4,400 ansi lumens cuong do s&aacute;ng m&agrave;u: 4,400 ansi lumens do ph&acirc;n giai thuc: xga (1024 x 768) do tuong phan: 15.000:1 b&oacute;ng d&egrave;n: tuoi tho 10,000 gio loa &acirc;m thanh : 16w chieu lech g&oacute;c: +/-30 do (doc, ngang) tr&igrave;nh chieu h&igrave;nh anh tu usb tr&igrave;nh chieu v&agrave; quan l&yacute; m&aacute;y chieu th&ocirc;ng qua mang lan cong usb-b (3 trong 1) tr&igrave;nh chieu h&igrave;nh anh, &acirc;m '),
(93, 'Máy chiếu Sony', 'may-chieu-sony-dw240_1587961328.jpg', '', '<strong>M&aacute;y chiếu Sony</strong><br />\n<ul>\n<li>Thương hi&ecirc;̣u: Sony</li>\n<li>Bảo hành: 12 tháng</li>\n<li>Cho h&igrave;nh ảnh sắc n&eacute;t, ch&acirc;n thực</li>\n<li>Th&iacute;ch hợp cho phòng học, ph&ograve;ng hội nghị, v.v</li>\n<li>Hiệu quả v&agrave; dễ sử dụng</li>\n</ul>', 0, 1652, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 04:23:39', '2020-04-27 05:36:40', 'may chieu sony', 'may chieu sony m&aacute;y chieu sony thuong hi&ecirc;̣u: sony bảo hành: 12 tháng cho h&igrave;nh anh sac n&eacute;t, ch&acirc;n thuc th&iacute;ch hop cho phòng hoc, ph&ograve;ng hoi nghi, v.v hieu qua v&agrave; de su dung '),
