(95, 'Máy chiếu BenQ', 'may-chieu-benq-th683-3-avpsi_1587968723.jpg', '', '<strong>M&aacute;y chiếu BenQ</strong><br />\n<ul>\n<li>Thương hi&ecirc;̣u: BenQ</li>\n<li>Bảo hành: 12 tháng</li>\n<li>Cho h&igrave;nh ảnh sắc n&eacute;t, ch&acirc;n thực</li>\n<li>Th&iacute;ch hợp cho phòng học, ph&ograve;ng hội nghị, giải trí v.v</li>\n<li>Hiệu quả v&agrave; dễ sử dụng</li>\n</ul>', 0, 1578, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 05:44:09', '2020-04-27 06:29:31', 'may chieu benq', 'may chieu benq m&aacute;y chieu benq thuong hi&ecirc;̣u: benq bảo hành: 12 tháng cho h&igrave;nh anh sac n&eacute;t, ch&acirc;n thuc th&iacute;ch hop cho phòng hoc, ph&ograve;ng hoi nghi, giải trí v.v hieu qua v&agrave; de su dung '),
(96, 'Máy chấm công Ronald Jack', 'may-chqm-cong-ronald-jack-rj3400-avpsi_1587982074.jpg', '', '<strong>M&aacute;y chấm c&ocirc;ng Ronald Jack RJ3400</strong><br />\n<ul>\n<li>Thương hi&ecirc;̣u:&nbsp;Ronad Jack&nbsp;</li>\n<li>C&ocirc;ng nghệ mới nhất 2020</li>\n<li>M&agrave;n h&igrave;nh: 2.8 \"TFT</li>\n<li>C&ocirc;ng suất v&acirc;n tay: 3000 dấu v&acirc;n tay + 3000 thẻ</li>\n<li>Mỗi người c&oacute; thể khai b&aacute;o 10 dấu v&acirc;n tay</li>\n<li>Dung lượng bộ nhớ: 80000 lần giao dịch</li>\n<li>Bảo mật cao: kh&ocirc;ng chấm c&ocirc;ng d&ugrave;m được.</li>\n<li>Đặc biệt với phầm mềm chấm c&ocirc;ng tiếng Việt Wise Eye On39</li>\n<li>Chấm c&ocirc;ng theo ca, giờ h&agrave;nh ch&aacute;nh&hellip;ph&ugrave; hợp với nhu cầu của c&aacute;c c&ocirc;ng ty, xưởng sản xuất, nh&agrave; h&agrave;ng,</li>\n<li>Xuất dữ liệu chấm c&ocirc;ng ra Excel ( bảng chi tiết, tổng hợp ng&agrave;y/ tuần/ th&aacute;ng&hellip;)</li>\n</ul>', 0, 1762, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 08:39:13', '2020-04-27 12:06:43', 'may cham cong ronald jack', 'may cham cong ronald jack m&aacute;y cham c&ocirc;ng ronald jack rj3400 thuong hi&ecirc;̣u:&nbsp;ronad jack&nbsp; c&ocirc;ng nghe moi nhat 2020 m&agrave;n h&igrave;nh: 2.8 \"tft c&ocirc;ng suat v&acirc;n tay: 3000 dau v&acirc;n tay + 3000 the moi nguoi c&oacute; the khai b&aacute;o 10 dau v&acirc;n tay dung luong bo nho: 80000 lan giao dich bao mat cao: kh&ocirc;ng cham c&ocirc;ng d&ugrave;m duoc. dac biet voi pham mem cham c&ocirc;ng tieng viet wise eye on39 cham c&ocirc;ng theo ca, gio h&agrave;nh ch&aacute;nh&hellip;ph&ugrave; hop voi nhu cau cua c&aacute;c c&ocirc;ng ty, xuong san xuat, nh&agrave; h&agrave;ng, xuat du lieu cham c&ocirc;ng ra excel ( bang chi tiet, tong hop ng&agrave;y/ tuan/ th&aacute;ng&hellip;) '),
(97, 'Máy chấm công Bosser', 'may-cham-cong-bosser-f385t-avpsi_1587981796.jpg', '', '<strong>M&aacute;y chấm c&ocirc;ng Bosser</strong><br />\n<ul>\n<li>Thương hi&ecirc;̣u:&nbsp;Bosser</li>\n<li>Bảo hành: chính hãng</li>\n<li>Máy hoạt đ&ocirc;̣ng nhanh, &ocirc;̉n định</li>\n<li>Quản lý nh&acirc;n vi&ecirc;n ti&ecirc;̣n lợi</li>\n<li>Thi&ecirc;́t k&ecirc;́ gọn gàng, d&ecirc;̃ cài đặt, d&ecirc;̃ sử dụng</li>\n</ul>', 0, 1590, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 09:57:14', '2020-04-27 11:29:32', 'may cham cong bosser', 'may cham cong bosser m&aacute;y cham c&ocirc;ng bosser thuong hi&ecirc;̣u:&nbsp;bosser bảo hành: chính hãng máy hoạt d&ocirc;̣ng nhanh, &ocirc;̉n dịnh quản lý nh&acirc;n vi&ecirc;n ti&ecirc;̣n lọi thi&ecirc;́t k&ecirc;́ gọn gàng, d&ecirc;̃ cài dạt, d&ecirc;̃ sủ dụng '),
(98, 'Máy chấm công ZK Teco', 'may-cham-cong-zkteco-silk-101ta-avpsi-500x500_1587986726.jpg', '', '<strong>M&aacute;y chấm c&ocirc;ng ZK Teco</strong><br />\n<ul>\n<li>Thương hi&ecirc;̣u: ZK Teco</li>\n<li>Bảo hành: chính hãng</li>\n<li>Máy hoạt đ&ocirc;̣ng nhanh, &ocirc;̉n định</li>\n<li>Quản lý nh&acirc;n vi&ecirc;n ti&ecirc;̣n lợi</li>\n<li>Thi&ecirc;́t k&ecirc;́ gọn gàng, d&ecirc;̃ cài đặt , d&ecirc;̃ sử dụng</li>\n</ul>', 0, 1678, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 10:43:41', '2020-04-27 11:30:37', 'may cham cong zk teco', 'may cham cong zk teco m&aacute;y cham c&ocirc;ng zk teco thuong hi&ecirc;̣u: zk teco bảo hành: chính hãng máy hoạt d&ocirc;̣ng nhanh, &ocirc;̉n dịnh quản lý nh&acirc;n vi&ecirc;n ti&ecirc;̣n lọi thi&ecirc;́t k&ecirc;́ gọn gàng, d&ecirc;̃ cài dạt , d&ecirc;̃ sủ dụng '),
(99, 'Máy chấm công Wise Eye ', 'may-cham-cong-wise-eye-9079-avpsi-500x500_1587988977.jpg', '', '<strong>M&aacute;y chấm c&ocirc;ng Wise Eye </strong><br />\n<ul>\n<li>Thương hi&ecirc;̣u: Wise Eye</li>\n<li>Bảo hành: chính hãng</li>\n<li>Máy hoạt đ&ocirc;̣ng nhanh, &ocirc;̉n định</li>\n<li>Quản lý nh&acirc;n vi&ecirc;n ti&ecirc;̣n lợi</li>\n<li>Thi&ecirc;́t k&ecirc;́ gọn gàng, d&ecirc;̃ cài đặt , d&ecirc;̃ sử dụng.</li>\n</ul>', 0, 1625, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 11:31:22', '2020-04-27 15:41:37', 'may cham cong wise eye ', 'may cham cong wise eye m&aacute;y cham c&ocirc;ng wise eye thuong hi&ecirc;̣u: wise eye bảo hành: chính hãng máy hoạt d&ocirc;̣ng nhanh, &ocirc;̉n dịnh quản lý nh&acirc;n vi&ecirc;n ti&ecirc;̣n lọi thi&ecirc;́t k&ecirc;́ gọn gàng, d&ecirc;̃ cài dạt , d&ecirc;̃ sủ dụng. '),
(100, 'Máy in nhãn Epson', 'may-in-nhan-epson-tm-c3510-avpsi_1587994598.jpg', '', '<strong>M&aacute;y in nh&atilde;n m&agrave;u Epson TM-C3510</strong><span style=\"text-align: justify;\"><br />- <strong>M&aacute;y in nh&atilde;n m&agrave;u</strong> theo y&ecirc;u cầu <strong>Epson TM-C3510</strong> cho hiệu suất cao v&agrave; tiết kiệm chi ph&iacute;. In m&atilde; m&agrave;u, ảnh m&agrave;u l&agrave;m nổi bật th&ocirc;ng tin li&ecirc;n quan 1 c&aacute;ch dễ d&agrave;ng. Thiết kế ph&ugrave; hợp nhu cầu kh&aacute;ch h&agrave;ng với nhu cầu sản xuất với số lượng &iacute;t. TM-C3510 cho ph&eacute;p in nhiều loại nh&atilde;n kh&aacute;c nhau gi&uacute;p x&aacute;c định sản phẩm v&agrave; tăng hiệu quả sản xuất.<br />- <strong>Ưu đi&ecirc;̉m:</strong><br /></span>\n<div style=\"padding-left: 30px; text-align: justify;\"><span style=\"text-align: justify;\">&bull; Gi&uacute;p quản l&yacute; kho tốt hơn</span></div>\n<div style=\"padding-left: 30px; text-align: justify;\"><span style=\"text-align: justify;\">&bull; Chứng nhận chuẩn BS5609</span></div>\n<div style=\"padding-left: 30px; text-align: justify;\"><span style=\"text-align: justify;\">&bull; Chất lượng in cao cấp:&nbsp;Đảm bảo h&igrave;nh ảnh in sắc n&eacute;t tr&ecirc;n mỗi nh&atilde;n. C&ocirc;ng nghệ in phun MicroPiezo&reg; c&ugrave;ng với mực in DURABrite Ultra&reg; đảm bảo nh&atilde;n sinh động, r&otilde; r&agrave;ng.</span></div>\n<div style=\"padding-left: 30px; text-align: justify;\"><span style=\"text-align: justify;\">&bull; B&igrave;nh mực dung lượng cao:&nbsp;Với hộp mực CMYK, cho ph&eacute;p kh&ocirc;ng hao ph&iacute; mực v&agrave; gi&uacute;p in số lượng lớn li&ecirc;n tục với chi ph&iacute; giảm v&agrave; kh&ocirc;ng ảnh hưởng đến sản xuất.</span></div>\n<div style=\"padding-left: 30px; text-align: justify;\"><span style=\"text-align: justify;\">&bull; Đa dạng về giấy:&nbsp;In tr&ecirc;n nhiều loại giấy v&agrave; in nh&atilde;n m&agrave;u theo y&ecirc;u cầu trong bất kỳ m&ocirc;i trường n&agrave;o.</span></div>', 0, 1936, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 13:52:28', '2020-04-27 16:30:57', 'may in nhan epson', 'may in nhan epson m&aacute;y in nh&atilde;n m&agrave;u epson tm-c3510- m&aacute;y in nh&atilde;n m&agrave;u theo y&ecirc;u cau epson tm-c3510 cho hieu suat cao v&agrave; tiet kiem chi ph&iacute;. in m&atilde; m&agrave;u, anh m&agrave;u l&agrave;m noi bat th&ocirc;ng tin li&ecirc;n quan 1 c&aacute;ch de d&agrave;ng. thiet ke ph&ugrave; hop nhu cau kh&aacute;ch h&agrave;ng voi nhu cau san xuat voi so luong &iacute;t. tm-c3510 cho ph&eacute;p in nhieu loai nh&atilde;n kh&aacute;c nhau gi&uacute;p x&aacute;c dinh san pham v&agrave; tang hieu qua san xuat.- uu di&ecirc;̉m: &bull; gi&uacute;p quan l&yacute; kho tot hon &bull; chung nhan chuan bs5609 &bull; chat luong in cao cap:&nbsp;dam bao h&igrave;nh anh in sac n&eacute;t tr&ecirc;n moi nh&atilde;n. c&ocirc;ng nghe in phun micropiezo&reg; c&ugrave;ng voi muc in durabrite ultra&reg; dam bao nh&atilde;n sinh dong, r&otilde; r&agrave;ng. &bull; b&igrave;nh muc dung luong cao:&nbsp;voi hop muc cmyk, cho ph&eacute;p kh&ocirc;ng hao ph&iacute; muc v&agrave; gi&uacute;p in so luong lon li&ecirc;n tuc voi chi ph&iacute; giam v&agrave; kh&ocirc;ng anh huong den san xuat. &bull; da dang ve giay:&nbsp;in tr&ecirc;n nhieu loai giay v&agrave; in nh&atilde;n m&agrave;u theo y&ecirc;u cau trong bat ky m&ocirc;i truong n&agrave;o.'),
(101, 'Máy in nhãn Brother', 'may-in-nhan-brother-pt-d600-avpsi-500x500_1588000613.jpg', '', '<strong>M&aacute;y in nh&atilde;n Brother PT D600</strong>\n<div style=\"text-align: justify;\"><strong>- M&aacute;y in nh&atilde;n Brother</strong> PT D600 là d&ograve;ng m&aacute;y in nh&atilde;n chuy&ecirc;n dụng với khả năng di động thuận tiện cho c&aacute;c bộ phận quản l&yacute; t&agrave;i sản kiểm k&ecirc;, sử dụng để quản l&yacute; c&aacute;c thiết bị hạ tầng viễn th&ocirc;ng.</div>\n<strong>- Tính năng n&ocirc;̉i b&acirc;̣t</strong>\n<div style=\"padding-left: 30px; text-align: justify;\">&bull; Thương hiệu: Brother</div>\n<div style=\"padding-left: 30px; text-align: justify;\">&bull; Cỡ băng: Size 3.5mm, 6mm, 9mm, 12mm, 18mm, 24mm</div>\n<div style=\"padding-left: 30px; text-align: justify;\">&bull; Tốc độ in: up to 30mm/sec. (AC adapter); up to 20mm/sec (batteries)</div>\n<div style=\"padding-left: 30px; text-align: justify;\">&bull; Độ ph&acirc;n giải: 180 x 360 dpi</div>\n<div style=\"padding-left: 30px; text-align: justify;\">&bull; Gi&acirc;́y nhãn: PT-D600 Label Printer/ TZe Starter Tape 0.94\" (24mm) x 13.1\' (4m)</div>\n<div style=\"padding-left: 30px; text-align: justify;\">&bull; Chất lượng nh&atilde;n in vượt trội</div>\n<div style=\"padding-left: 30px; text-align: justify;\">&bull; Thi&ecirc;́t k&ecirc;́ nhỏ gọn dễ sử dụng, đem lại sự tiện lợi cho người dùng.</div>', 0, 1870, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 15:22:38', '2020-04-27 19:12:45', 'may in nhan brother', 'may in nhan brother m&aacute;y in nh&atilde;n brother pt d600 - m&aacute;y in nh&atilde;n brother pt d600 là d&ograve;ng m&aacute;y in nh&atilde;n chuy&ecirc;n dung voi kha nang di dong thuan tien cho c&aacute;c bo phan quan l&yacute; t&agrave;i san kiem k&ecirc;, su dung de quan l&yacute; c&aacute;c thiet bi ha tang vien th&ocirc;ng. - tính nang n&ocirc;̉i b&acirc;̣t &bull; thuong hieu: brother &bull; co bang: size 3.5mm, 6mm, 9mm, 12mm, 18mm, 24mm &bull; toc do in: up to 30mm/sec. (ac adapter); up to 20mm/sec (batteries) &bull; do ph&acirc;n giai: 180 x 360 dpi &bull; gi&acirc;́y nhãn: pt-d600 label printer/ tze starter tape 0.94\" (24mm) x 13.1\' (4m) &bull; chat luong nh&atilde;n in vuot troi &bull; thi&ecirc;́t k&ecirc;́ nho gon de su dung, dem lai su tien loi cho nguoi dùng.'),
(102, 'Máy in nhãn Zebra', 'may-in-nhan-zebra-k420d-avpsi_1588005771.jpg', '', '<strong>M&aacute;y in nh&atilde;n Zebra GK 420D</strong>\n<div style=\"text-align: justify;\"><strong>- M&aacute;y in nh&atilde;n Zebra GK 420D </strong>với&nbsp;cấu tạo vỏ nhựa nhẹ bền, kiểu d&aacute;ng đẹp dễ thiết kế đặt để tiện lợi tr&ecirc;n b&agrave;n l&agrave;m việc hoặc bất cứ kh&ocirc;ng gian hẹp n&agrave;o. Hơn nữa, Zebra GK 420T c&ograve;n k&egrave;m phụ kiện dễ d&agrave;ng lắp đặt v&agrave; th&aacute;o rời, l&agrave;m tăng những tiện &iacute;ch c&ocirc;ng nghệ cho người d&ugrave;ng. Model n&agrave;y th&iacute;ch hợp cho nhu cầu in nh&atilde;n cơ bản, kh&ocirc;ng thường xuy&ecirc;n với chi ph&iacute; vận h&agrave;nh thấp, an to&agrave;n.</div>\n<strong>- Tính năng n&ocirc;̉i b&acirc;̣t</strong><br />\n<ul>\n<li style=\"text-align: justify;\">Thương hiệu: Zebra</li>\n<li style=\"text-align: justify;\">Cỡ băng: Size 3.5mm, 6mm, 9mm, 12mm, 18mm, 24mm</li>\n<li style=\"text-align: justify;\">Tốc độ in: up to 5&Prime; (127 mm) per second</li>\n<li style=\"text-align: justify;\">Độ ph&acirc;n giải: 203 dpi (8 dots/mm)</li>\n<li style=\"text-align: justify;\">Chất lượng nh&atilde;n in vượt trội</li>\n<li style=\"text-align: justify;\">Thi&ecirc;́t k&ecirc;́ nhỏ gọn dễ sử dụng, đem lại sự tiện lợi cho người dùng.</li>\n</ul>', 0, 1776, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 16:19:29', '2020-04-27 17:18:26', 'may in nhan zebra', 'may in nhan zebra m&aacute;y in nh&atilde;n zebra gk 420d - m&aacute;y in nh&atilde;n zebra gk 420d vói&nbsp;cau tao vo nhua nhe ben, kieu d&aacute;ng dep de thiet ke dat de tien loi tr&ecirc;n b&agrave;n l&agrave;m viec hoac bat cu kh&ocirc;ng gian hep n&agrave;o. hon nua, zebra gk 420t c&ograve;n k&egrave;m phu kien de d&agrave;ng lap dat v&agrave; th&aacute;o roi, l&agrave;m tang nhung tien &iacute;ch c&ocirc;ng nghe cho nguoi d&ugrave;ng. model n&agrave;y th&iacute;ch hop cho nhu cau in nh&atilde;n co ban, kh&ocirc;ng thuong xuy&ecirc;n voi chi ph&iacute; van h&agrave;nh thap, an to&agrave;n. - tính nang n&ocirc;̉i b&acirc;̣t thuong hieu: zebra co bang: size 3.5mm, 6mm, 9mm, 12mm, 18mm, 24mm toc do in: up to 5&prime; (127 mm) per second do ph&acirc;n giai: 203 dpi (8 dots/mm) chat luong nh&atilde;n in vuot troi thi&ecirc;́t k&ecirc;́ nho gon de su dung, dem lai su tien loi cho nguoi dùng. '),
(103, 'Máy in kim Epson', 'may-in-kim-epson-lq-310-avpsi-500x500_1588013972.jpg', '', '<strong>M&aacute;y in kim Epson LQ-310</strong>\n<div style=\"text-align: justify;\"><strong>- M&aacute;y in Epson LQ-310</strong> được hỗ trợ bộ nhớ đệm 128KB c&oacute; dung lượng gấp đ&ocirc;i so với c&aacute;c m&aacute;y in trước, t&iacute;nh năng n&agrave;y gi&uacute;p tốc độ m&aacute;y in l&ecirc;n đến 416 k&yacute; tự/gi&acirc;y, nhanh gần 40% so với d&ograve;ng m&aacute;y LQ 300. D&ograve;ng m&aacute;y in n&agrave;y ch&iacute;nh l&agrave; lựa chọn tiết kiệm v&agrave; th&ocirc;ng minh cho c&aacute;c doanh nghiệp cần in ấn h&oacute;a đơn.<br /><strong><strong>- Tính năng n&ocirc;̉i b&acirc;̣t<br /></strong></strong>\n<div style=\"padding-left: 30px;\">&bull; Thương hiệu:&nbsp;Epson</div>\n<div style=\"padding-left: 30px;\">&bull; Loại m&aacute;y in: M&aacute;y in kim</div>\n<div style=\"padding-left: 30px;\">&bull; Khổ giấy in: Rộng 100-257mm, D&agrave;i 100-364mm</div>\n<div style=\"padding-left: 30px;\">&bull; Tốc độ in: 416 k&iacute; tự/gi&acirc;y</div>\n<div style=\"padding-left: 30px;\">&bull; Gi&acirc;́y nhãn: PT-D600 Label Printer/ TZe Starter Tape 0.94\" (24mm) x 13.1\' (4m)<br />&bull; M&atilde; mực in: Ribbon Epson S015639/ S015634 (10m)/ Vmax Ribbon Epson S015639</div>\n<div style=\"padding-left: 30px;\">&bull; D&ograve;ng m&aacute;y in kim cực nhanh.<br />&bull; Tuổi thọ cao hơn, kết nối linh hoạt</div>\n<div style=\"padding-left: 30px;\">&bull; Hiệu năng cao với t&agrave;i liệu in nhiều bản.</div>\n<br /><br /></div>', 0, 1926, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 19:09:30', '2020-04-27 19:19:06', 'may in kim epson', 'may in kim epson m&aacute;y in kim epson lq-310 - m&aacute;y in epson lq-310 duoc ho tro bo nho dem 128kb c&oacute; dung luong gap d&ocirc;i so voi c&aacute;c m&aacute;y in truoc, t&iacute;nh nang n&agrave;y gi&uacute;p toc do m&aacute;y in l&ecirc;n den 416 k&yacute; tu/gi&acirc;y, nhanh gan 40% so voi d&ograve;ng m&aacute;y lq 300. d&ograve;ng m&aacute;y in n&agrave;y ch&iacute;nh l&agrave; lua chon tiet kiem v&agrave; th&ocirc;ng minh cho c&aacute;c doanh nghiep can in an h&oacute;a don.- tính nang n&ocirc;̉i b&acirc;̣t &bull; thuong hieu:&nbsp;epson &bull; loai m&aacute;y in: m&aacute;y in kim &bull; kho giay in: rong 100-257mm, d&agrave;i 100-364mm &bull; toc do in: 416 k&iacute; tu/gi&acirc;y &bull; gi&acirc;́y nhãn: pt-d600 label printer/ tze starter tape 0.94\" (24mm) x 13.1\' (4m)&bull; m&atilde; muc in: ribbon epson s015639/ s015634 (10m)/ vmax ribbon epson s015639 &bull; d&ograve;ng m&aacute;y in kim cuc nhanh.&bull; tuoi tho cao hon, ket noi linh hoat &bull; hieu nang cao voi t&agrave;i lieu in nhieu ban. '),
(104, 'Máy in kim Oki', 'may-in-kim-oki-ml-1190-plus-avpsi_3-500x500_1588017524.jpg', '', '<strong>M&aacute;y in kim Oki ML 1190 Plus</strong>\n<div style=\"text-align: justify;\"><strong>- M&aacute;y in kim Oki ML 1190 Plus </strong>với thi&ecirc;́t k&ecirc;́&nbsp;24 kim tốc độ cao, t&iacute;nh năng hoạt động bền bỉ, &iacute;t hư hao, chi ph&iacute; đầu tư thấp, đ&aacute;p ứng nhiều nhu cầu sử dụng việc in c&aacute;c phiếu thu chi bằng giấy nhiều li&ecirc;n (5 li&ecirc;n), h&oacute;a đơn t&iacute;nh tiền v&agrave; cả những h&oacute;a đơn t&agrave;i ch&iacute;nh, kế to&aacute;n quan trọng.<br /><strong><strong>- Tính năng n&ocirc;̉i b&acirc;̣t<br /></strong></strong>\n<div style=\"padding-left: 30px;\">&bull; Thương hiệu: Oki</div>\n<div style=\"padding-left: 30px;\">&bull; Loại m&aacute;y in: M&aacute;y in kim 24 kim</div>\n<div style=\"padding-left: 30px;\">&bull; Khổ giấy in: Giấy li&ecirc;n tục 76,2 - 245mm</div>\n<div style=\"padding-left: 30px;\">&bull; Tốc độ in: 333 k&iacute; tự/gi&acirc;y</div>\n<div style=\"padding-left: 30px;\">&bull; Gi&acirc;́y nhãn: PT-D600 Label Printer/ TZe Starter Tape 0.94\" (24mm) x 13.1\' (4m)<br />&bull; M&atilde; mực in: Ribbon Oki ML-1120/1190 (4 tri&ecirc;̣u ký tự).</div>\n<div style=\"padding-left: 30px;\">&bull;&nbsp;Thiết kế th&acirc;n thiện, nhỏ gọn d&ecirc;̃ sử dụng.<br />&bull; B&ecirc;̀n bỉ, tuổi thọ máy cao.&nbsp;</div>\n<div style=\"padding-left: 30px;\">&bull;&nbsp;C&oacute; khả năng tinh chỉnh vị tr&iacute; đầu kim l&ecirc;n xuống gi&uacute;p in đ&uacute;ng vị tr&iacute; theo chuẩn mẫu h&oacute;a đơn đặc th&ugrave; theo từng nhu cầu của doanh nghiệp chỉ bằng v&agrave;i thao t&aacute;c đơn giản.</div>\n</div>', 0, 1870, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 19:20:03', '2020-04-27 20:11:35', 'may in kim oki', 'may in kim oki m&aacute;y in kim oki ml 1190 plus - m&aacute;y in kim oki ml 1190 plus vói thi&ecirc;́t k&ecirc;́&nbsp;24 kim toc do cao, t&iacute;nh nang hoat dong ben bi, &iacute;t hu hao, chi ph&iacute; dau tu thap, d&aacute;p ung nhieu nhu cau su dung viec in c&aacute;c phieu thu chi bang giay nhieu li&ecirc;n (5 li&ecirc;n), h&oacute;a don t&iacute;nh tien v&agrave; ca nhung h&oacute;a don t&agrave;i ch&iacute;nh, ke to&aacute;n quan trong.- tính nang n&ocirc;̉i b&acirc;̣t &bull; thuong hieu: oki &bull; loai m&aacute;y in: m&aacute;y in kim 24 kim &bull; kho giay in: giay li&ecirc;n tuc 76,2 - 245mm &bull; toc do in: 333 k&iacute; tu/gi&acirc;y &bull; gi&acirc;́y nhãn: pt-d600 label printer/ tze starter tape 0.94\" (24mm) x 13.1\' (4m)&bull; m&atilde; muc in: ribbon oki ml-1120/1190 (4 tri&ecirc;̣u ký tụ). &bull;&nbsp;thiet ke th&acirc;n thien, nho gon d&ecirc;̃ sủ dụng.&bull; b&ecirc;̀n bỉ, tuoi tho máy cao.&nbsp; &bull;&nbsp;c&oacute; kha nang tinh chinh vi tr&iacute; dau kim l&ecirc;n xuong gi&uacute;p in d&uacute;ng vi tr&iacute; theo chuan mau h&oacute;a don dac th&ugrave; theo tung nhu cau cua doanh nghiep chi bang v&agrave;i thao t&aacute;c don gian. '),
(105, 'Tổng đài điện thoại Panasonic', 'tong-dai-panasonic-kx-tes824_1588023288.jpg', '', '<strong>T&ocirc;̉ng đài đi&ecirc;̣n thoại Panasonic KX-TES824</strong><br />\n<div style=\"text-align: justify;\"><strong>- Tổng đ&agrave;i Panasonic KX-TES824</strong> l&agrave; một trong những d&ograve;ng sản phẩm phổ biến nhất trong hệ thống tổng đ&agrave;i điện thoại nội bộ cho doanh nghiệp hiện nay n&oacute;i chung v&agrave; của tổng đ&agrave;i Panasonic n&oacute;i ri&ecirc;ng. Tổng đ&agrave;i n&agrave;y c&oacute; sự linh hoạt về t&iacute;nh năng, cấu h&igrave;nh, l&agrave; giải ph&aacute;p ho&agrave;n hảo cho doanh nghiệp vừa v&agrave; nhỏ. Hệ thống th&iacute;ch hợp với c&aacute;c văn ph&ograve;ng c&ocirc;ng ty c&oacute; số lượng nh&acirc;n vi&ecirc;n dưới 24 người hoặc với kh&aacute;ch sạn nhỏ hay nh&agrave; nghỉ.</div>\n- <strong>Tính năng chính</strong>\n<div style=\"padding-left: 30px; text-align: justify;\">&bull; Tổng đ&agrave;i panasonic 3 đường v&agrave;o bưu điện v&agrave; ra 8 m&aacute;y lẻ</div>\n<div style=\"padding-left: 30px; text-align: justify;\">&bull; Khả năng mở rộng tối đa 24 m&aacute;y lẻ, ph&ugrave; hợp cho c&aacute;c văn ph&ograve;ng, nh&agrave; xưởng, kh&aacute;ch sạn, nh&agrave; nghỉ.</div>\n<div style=\"padding-left: 30px; text-align: justify;\">&bull; T&iacute;ch hợp sẵn lời ch&agrave;o 1 k&ecirc;nh, hiển thị số nội bộ.</div>', 0, 2107, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 21:54:13', '2020-04-27 21:56:56', 'tong dai dien thoai panasonic', 'tong dai dien thoai panasonic t&ocirc;̉ng dài di&ecirc;̣n thoại panasonic kx-tes824 - tong d&agrave;i panasonic kx-tes824 l&agrave; mot trong nhung d&ograve;ng san pham pho bien nhat trong he thong tong d&agrave;i dien thoai noi bo cho doanh nghiep hien nay n&oacute;i chung v&agrave; cua tong d&agrave;i panasonic n&oacute;i ri&ecirc;ng. tong d&agrave;i n&agrave;y c&oacute; su linh hoat ve t&iacute;nh nang, cau h&igrave;nh, l&agrave; giai ph&aacute;p ho&agrave;n hao cho doanh nghiep vua v&agrave; nho. he thong th&iacute;ch hop voi c&aacute;c van ph&ograve;ng c&ocirc;ng ty c&oacute; so luong nh&acirc;n vi&ecirc;n duoi 24 nguoi hoac voi kh&aacute;ch san nho hay nh&agrave; nghi. - tính nang chính &bull; tong d&agrave;i panasonic 3 duong v&agrave;o buu dien v&agrave; ra 8 m&aacute;y le &bull; kha nang mo rong toi da 24 m&aacute;y le, ph&ugrave; hop cho c&aacute;c van ph&ograve;ng, nh&agrave; xuong, kh&aacute;ch san, nh&agrave; nghi. &bull; t&iacute;ch hop san loi ch&agrave;o 1 k&ecirc;nh, hien thi so noi bo.'),
(106, 'Tổng đài điện thoại Grandstream', 'tong-dai-ip-grandstream-ucm-6204-500x500_1588026392.jpg', '', '<strong>Tổng đ&agrave;i IP Grandstream UCM-6204</strong>\n<div style=\"text-align: justify;\">- Tổng đ&agrave;i IP Grandstream UCM-6204 l&agrave; d&ograve;ng sản phẩm tổng đ&agrave;i IP (Unified Communication) ho&agrave;n to&agrave;n mới đề xuất cho các doanh nghiệp m&ocirc; hình trung bình. Thiết kế v&agrave; trang bị những phần cứng cao cấp v&agrave; ứng dụng phần mềm Asterisk, tổng đ&agrave;i IP Grandstream UCM-6204 cung cấp cho người d&ugrave;ng những tr&atilde;i nghiệm tuyệt với c&ocirc;ng nghệ truyền th&ocirc;ng VoIP ti&ecirc;n tiến nhất với c&aacute;c ứng dụng Voice &ndash; Video &ndash; Fax &ndash; Data. C&agrave;i đặt v&agrave; vận h&agrave;nh cực kỳ nhanh ch&oacute;ng, đơn giản.</div>\n- <strong>Tính năng chính</strong>\n<div style=\"padding-left: 30px; text-align: justify;\">&bull; Tổng đ&agrave;i IP Grandstream UCM-6204 4 đường v&agrave;o bưu điện analog, ra 2 m&aacute;y lẻ analog và 500 m&aacute;y lẻ IP SIP.</div>\n<div style=\"padding-left: 30px; text-align: justify;\">&bull;&nbsp;2 cổng mạng 10/100/1000 Mbps <br />&bull; T&iacute;ch hợp sẵn cổng nối USB v&agrave; khe cắm thẻ nhớ SD<br />&bull; T&iacute;ch hợp sẵn 4 cổng PSTN kết nối 2 đường bưu điện (Khi mất điện tự động 2 cổng v&agrave;o sẽ kết nối 2 cổng ra analog)</div>\n<div style=\"padding-left: 30px; text-align: justify;\"></div>', 0, 2022, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-27 22:25:37', '2020-04-27 22:33:20', 'tong dai dien thoai grandstream', 'tong dai dien thoai grandstream tong d&agrave;i ip grandstream ucm-6204 - tong d&agrave;i ip grandstream ucm-6204 l&agrave; d&ograve;ng san pham tong d&agrave;i ip (unified communication) ho&agrave;n to&agrave;n moi de xuat cho các doanh nghiep m&ocirc; hình trung bình. thiet ke v&agrave; trang bi nhung phan cung cao cap v&agrave; ung dung phan mem asterisk, tong d&agrave;i ip grandstream ucm-6204 cung cap cho nguoi d&ugrave;ng nhung tr&atilde;i nghiem tuyet voi c&ocirc;ng nghe truyen th&ocirc;ng voip ti&ecirc;n tien nhat voi c&aacute;c ung dung voice &ndash; video &ndash; fax &ndash; data. c&agrave;i dat v&agrave; van h&agrave;nh cuc ky nhanh ch&oacute;ng, don gian. - tính nang chính &bull; tong d&agrave;i ip grandstream ucm-6204 4 duong v&agrave;o buu dien analog, ra 2 m&aacute;y le analog và 500 m&aacute;y le ip sip. &bull;&nbsp;2 cong mang 10/100/1000 mbps &bull; t&iacute;ch hop san cong noi usb v&agrave; khe cam the nho sd&bull; t&iacute;ch hop san 4 cong pstn ket noi 2 duong buu dien (khi mat dien tu dong 2 cong v&agrave;o se ket noi 2 cong ra analog) '),
(107, 'Laptop Acer Aspire E5-476-58KG NX.GRDSV.001 i5-8250U/4GB/1TB', 'laptop_acer_e5-476-58kg-1-avpsi_1588042136.jpg', '', '<span style=\"font-size: 13pt;\"><strong>Laptop Acer Aspire E5-476-58KG (NX.GRDSV.001) (14\" FHD/i5-8250U/4GB/1TB HDD/UHD 620/Linux/2 kg)</strong></span>\n<div style=\"padding-left: 30px;\"><br />&bull; CPU: Intel&reg; Core i5-8250U 1.6Ghz Upto 3.4GHz 6MB Cache L3</div>\n<div style=\"padding-left: 30px;\">&bull; RAM: 4GB DDR4 2400MHz</div>\n<div style=\"padding-left: 30px;\">&bull; HDD: 1TB HDD - 5400rpm</div>\n<div style=\"padding-left: 30px;\">&bull; VGA: Intel HD Graphics 620</div>\n<div style=\"padding-left: 30px;\">&bull; OS: Free DOS</div>\n<div style=\"padding-left: 30px;\">&bull; DISPLAY: 14\" LED Anti-Glare ComfyView Full HD - 1920 x 1080</div>\n<div style=\"padding-left: 30px;\">NETWORK: Wireless: 802.11 ac Lan: 10/100/1000 Mbps - Bluetooth: V4.0\"</div>\n<div style=\"text-align: justify;\"><br />Aspire thuộc d&ograve;ng Laptop đa năng ph&ugrave; hợp với nhiều mục đ&iacute;ch sử dụng của Acer. Với thiết kế thuộc dạng k&iacute;ch thước tầm trung và giá t&ocirc;́t, E5-476-58KG ph&ugrave; hợp với cả d&acirc;n văn ph&ograve;ng, sinh vi&ecirc;n, học sinh,&hellip;</div>\n<div style=\"text-align: justify;\">Trong tầm gi&aacute; chỉ hơn 10 triệu, ch&uacute;ng ta đ&atilde; chiếc m&aacute;y c&oacute; cấu h&igrave;nh kh&aacute; tốt Intel Core i5 8250U, m&agrave;n h&igrave;nh rộng 14 inch độ ph&acirc;n giải chuẩn Full HD 1920 x 1080 pxl v&agrave; c&ocirc;ng nghệ Acer BluelightShield bảo vệ mắt khi phải l&agrave;m việc thường xuy&ecirc;n tr&ecirc;n m&aacute;y t&iacute;nh.</div>', 0, 1854, 0.00, 'active', 1000, '', '', 0, 'publish', 1, '', '', '', '', '', '', '2020-04-28 02:49:28', '2020-04-28 07:55:07', 'laptop acer aspire e5-476-58kg nx.grdsv.001 i5-8250u/4gb/1tb', 'laptop acer aspire e5-476-58kg nx.grdsv.001 i5-8250u/4gb/1tb laptop acer aspire e5-476-58kg (nx.grdsv.001) (14\" fhd/i5-8250u/4gb/1tb hdd/uhd 620/linux/2 kg) &bull; cpu: intel&reg; core i5-8250u 1.6ghz upto 3.4ghz 6mb cache l3 &bull; ram: 4gb ddr4 2400mhz &bull; hdd: 1tb hdd - 5400rpm &bull; vga: intel hd graphics 620 &bull; os: free dos &bull; display: 14\" led anti-glare comfyview full hd - 1920 x 1080 network: wireless: 802.11 ac lan: 10/100/1000 mbps - bluetooth: v4.0\" aspire thuoc d&ograve;ng laptop da nang ph&ugrave; hop voi nhieu muc d&iacute;ch su dung cua acer. voi thiet ke thuoc dang k&iacute;ch thuoc tam trung và giá t&ocirc;́t, e5-476-58kg ph&ugrave; hop voi ca d&acirc;n van ph&ograve;ng, sinh vi&ecirc;n, hoc sinh,&hellip; trong tam gi&aacute; chi hon 10 trieu, ch&uacute;ng ta d&atilde; chiec m&aacute;y c&oacute; cau h&igrave;nh kh&aacute; tot intel core i5 8250u, m&agrave;n h&igrave;nh rong 14 inch do ph&acirc;n giai chuan full hd 1920 x 1080 pxl v&agrave; c&ocirc;ng nghe acer bluelightshield bao ve mat khi phai l&agrave;m viec thuong xuy&ecirc;n tr&ecirc;n m&aacute;y t&iacute;nh.');
