INSERT INTO `product_translations` (`id`, `product_id`, `lang`, `title`, `description`, `content`, `created_at`, `updated_at`) VALUES
(1, 1, 'en', 'Đồng hồ đeo tay App Watch(EN)', 'Được sản xuất độc quyền tại Mỹ, đồng hồ App Watch mang lại sự lịch lãm và sang trọng cho khách hàng quý phái. Được sự đánh giá cao từ giới chuyên môn App Watch dần khẳng định được tên tuổi của mình trên thị trường thế giới.(EN)', '<h6>Thiết kế đồng hồ Apple Watch.</h6>\n<p>Đồng hồ App Watch c&oacute; thiết kế Unibody nguy&ecirc;n khối, chất liệu bằng th&eacute;p kh&ocirc;ng gỉ, nh&ocirc;m, hoặc v&agrave;ng 18 karat t&ugrave;y phi&ecirc;n bản kh&aacute;c nhau. Mặt đồng hồ c&oacute; kiểu d&aacute;ng chữ nhật bo tr&ograve;n v&agrave; l&agrave;m bằng chất liệu sapphire chống va đập, chống xước cao cấp. Bạn c&oacute; hai k&iacute;ch thước mặt đồng hồ để lựa chọn l&agrave; 38mm v&agrave; 42mm. Với cổ tay b&igrave;nh thường người Việt Nam th&igrave; 38mm c&oacute; lẽ l&agrave; hợp l&yacute; hơn. Apple Watch c&oacute; khả năng chống nước v&agrave; 6 lựa chọn d&acirc;y đeo kh&aacute;c nhau</p>\n<br />\n<h6>C&aacute;c phi&ecirc;n bản đồng hồ App Watch</h6>\n<p>App Watch mang đến cho người d&ugrave;ng rất nhiều lựa chọn khi ngo&agrave;i việc c&oacute; hai k&iacute;ch thước m&agrave;n h&igrave;nh l&agrave; 38mm v&agrave; 42mm, chiếc đồng hồ n&agrave;y c&oacute; ba phi&ecirc;n bản chất liệu kh&aacute;c nhau c&ugrave;ng nhiều lựa chọn d&acirc;y đeo. Do đ&oacute; bạn sẽ c&oacute; h&agrave;ng chục phi&ecirc;n bản kh&aacute;c nhau để lựa chọn. Để người d&ugrave;ng tiện ph&acirc;n biệt, Apple đ&atilde; chia đồng hồ Apple Watch th&agrave;nh ba nh&oacute;m ch&iacute;nh: App Watch, App Watch Sport, App Watch Edition</p>\n<br />\n<h6>T&iacute;nh năng của đồng hồ App Watch</h6>\n<p>Nhắn tin, C&aacute; nh&acirc;n h&oacute;a h&igrave;nh ảnh, Digital Touch, Gọi điện, Siri, Bản đồ, nghe nhạc,...</p>', '2019-12-19 02:54:42', '2019-12-19 03:07:38'),
(2, 2, 'en', 'Đồng hồ đeo tay App Watch 1 (EN)', 'Được sản xuất độc quyền tại Mỹ, đồng hồ App Watch mang lại sự lịch lãm và sang trọng cho khách hàng quý phái. Được sự đánh giá cao từ giới chuyên môn App Watch dần khẳng định được tên tuổi của mình trên thị trường thế giới.', '<h6>Thiết kế đồng hồ Apple Watch.</h6>\n<p>Đồng hồ App Watch c&oacute; thiết kế Unibody nguy&ecirc;n khối, chất liệu bằng th&eacute;p kh&ocirc;ng gỉ, nh&ocirc;m, hoặc v&agrave;ng 18 karat t&ugrave;y phi&ecirc;n bản kh&aacute;c nhau. Mặt đồng hồ c&oacute; kiểu d&aacute;ng chữ nhật bo tr&ograve;n v&agrave; l&agrave;m bằng chất liệu sapphire chống va đập, chống xước cao cấp. Bạn c&oacute; hai k&iacute;ch thước mặt đồng hồ để lựa chọn l&agrave; 38mm v&agrave; 42mm. Với cổ tay b&igrave;nh thường người Việt Nam th&igrave; 38mm c&oacute; lẽ l&agrave; hợp l&yacute; hơn. Apple Watch c&oacute; khả năng chống nước v&agrave; 6 lựa chọn d&acirc;y đeo kh&aacute;c nhau</p>\n<br />\n<h6>C&aacute;c phi&ecirc;n bản đồng hồ App Watch</h6>\n<p>App Watch mang đến cho người d&ugrave;ng rất nhiều lựa chọn khi ngo&agrave;i việc c&oacute; hai k&iacute;ch thước m&agrave;n h&igrave;nh l&agrave; 38mm v&agrave; 42mm, chiếc đồng hồ n&agrave;y c&oacute; ba phi&ecirc;n bản chất liệu kh&aacute;c nhau c&ugrave;ng nhiều lựa chọn d&acirc;y đeo. Do đ&oacute; bạn sẽ c&oacute; h&agrave;ng chục phi&ecirc;n bản kh&aacute;c nhau để lựa chọn. Để người d&ugrave;ng tiện ph&acirc;n biệt, Apple đ&atilde; chia đồng hồ Apple Watch th&agrave;nh ba nh&oacute;m ch&iacute;nh: App Watch, App Watch Sport, App Watch Edition</p>\n<br />\n<h6>T&iacute;nh năng của đồng hồ App Watch</h6>\n<p>Nhắn tin, C&aacute; nh&acirc;n h&oacute;a h&igrave;nh ảnh, Digital Touch, Gọi điện, Siri, Bản đồ, nghe nhạc,...</p>', '2019-12-19 03:08:46', '2019-12-19 03:08:46'),
